import random
import math
import random

from typing import Any


class CheerEffect:
    def __init__(self, x, y, kind, owner_id):
        self.x = x
        self.y = y
        self.radius = 2
        self.kind = kind
        self.damage = 0
        self.owner_id = owner_id
        self.duration = 5.0
        self.active = True

class HomingMissileHazard:
    def __init__(self, id, x, y, radius, kind, damage):
        self.id = id
        self.x = x
        self.y = y
        self.radius = radius
        self.kind = kind
        self.damage = damage
        self.owner_id = None
        self.active = True


class LaserBeamNode:
    pass

class Action:


    def _award_xp(self, ball, amount, world=None) -> None:
        if not getattr(ball, "alive", False) or getattr(ball, "ball_type", None) == "spectator":
            return

        ball.experience = getattr(ball, "experience", 0.0) + amount
        ball.level = getattr(ball, "level", 1)

        while ball.experience >= 100 * ball.level:
            ball.experience -= 100 * ball.level
            ball.level += 1

            # Evolution mechanics
            if ball.level == 5 or ball.level == 10:
                evolutions = {
                    "warrior": ["paladin", "berserker"],
                    "mage": ["warlock", "necromancer"],
                    "rogue": ["ninja", "assassin"],
                    "tank": ["guardian", "juggernaut"],
                    "ranger": ["sniper", "bounty_hunter"],
                    "healer": ["monk", "druid"],
                    # Tier 2 evolutions
                    "paladin": ["templar", "guardian"],
                    "berserker": ["juggernaut", "brawler"],
                    "warlock": ["chaos", "necromancer"],
                    "necromancer": ["vampire", "warlock"],
                    "ninja": ["phantom", "assassin"],
                    "assassin": ["phantom", "ninja"],
                    "guardian": ["paladin", "juggernaut"],
                    "juggernaut": ["berserker", "guardian"],
                    "sniper": ["bounty_hunter", "scout"],
                    "bounty_hunter": ["sniper", "scout"],
                    "monk": ["templar", "druid"],
                    "druid": ["monk", "templar"]
                }
                current_type = getattr(ball, "ball_type", "")
                if current_type in evolutions:
                    import random
                    new_type = random.choice(evolutions[current_type])
                    ball.ball_type = new_type

                    if hasattr(world, "add_event"):
                        world.add_event("evolution", {"ball": getattr(ball, "id", None), "old_type": current_type, "new_type": new_type, "level": ball.level})

                    if ball.level == 10 and random.random() < 0.3:
                        import copy
                        boss = copy.copy(ball)
                        boss.id = getattr(world, "next_id", random.randint(10000, 99999))
                        if hasattr(world, "next_id"):
                            world.next_id += 1

                        base_class_map = {
                            "paladin": "warrior", "berserker": "warrior", "templar": "warrior", "brawler": "warrior",
                            "warlock": "mage", "necromancer": "mage", "chaos": "mage", "vampire": "mage",
                            "ninja": "rogue", "assassin": "rogue", "phantom": "rogue",
                            "guardian": "tank", "juggernaut": "tank",
                            "sniper": "ranger", "bounty_hunter": "ranger", "scout": "ranger",
                            "monk": "healer", "druid": "healer"
                        }
                        boss_type = base_class_map.get(new_type, new_type)

                        boss.ball_type = boss_type
                        boss.is_world_boss = True
                        boss.team = "corrupted_bosses"

                        boss.max_hp = getattr(ball, "max_hp", 100) * 10
                        boss.hp = boss.max_hp
                        boss.damage = getattr(ball, "damage", 10) * 3
                        if hasattr(boss, "base_damage"):
                            boss.base_damage = getattr(ball, "base_damage", 10) * 3

                        boss.radius = getattr(ball, "radius", 15) * 2.0

                        boss.speed = getattr(ball, "speed", 100) * 1.5
                        if hasattr(boss, "base_speed"):
                            boss.base_speed = getattr(ball, "base_speed", 100) * 1.5

                        boss.x = getattr(boss, "x", 0) + random.choice([-200, 200])
                        boss.y = getattr(boss, "y", 0) + random.choice([-200, 200])

                        boss.cosmetic_aura_color = (0.0, 0.0, 0.0, 1.0)
                        boss.cosmetic_aura_scale = 3.0

                        if hasattr(world, "balls"):
                            world.balls.append(boss)
                        if hasattr(world, "add_event"):
                            world.add_event("world_boss_spawned", {"boss_id": boss.id, "boss_type": boss_type})

            # Apply dynamic cosmetic aura scaling
            if not hasattr(ball, "cosmetic_aura_scale"):
                ball.cosmetic_aura_scale = 1.0
            ball.cosmetic_aura_scale += 0.2

            # Change color based on level
            colors = [(0.0, 1.0, 0.0, 0.5), (0.0, 0.0, 1.0, 0.6), (1.0, 0.0, 1.0, 0.7), (1.0, 0.0, 0.0, 0.8), (1.0, 1.0, 0.0, 1.0)]
            ball.cosmetic_aura_color = colors[min(ball.level - 1, len(colors) - 1)]

            # Apply random stat buff
            import random
            stat = random.choice(["max_hp", "damage", "speed"])
            if stat == "max_hp":
                ball.max_hp = getattr(ball, "max_hp", 100) * 1.1
                ball.hp = getattr(ball, "hp", ball.max_hp) + getattr(ball, "max_hp", 100) * 0.1
                if ball.hp > ball.max_hp: ball.hp = ball.max_hp
            elif stat == "damage":
                ball.damage = getattr(ball, "damage", 10) * 1.1
                if hasattr(ball, "base_damage"):
                    ball.base_damage *= 1.1
            elif stat == "speed":
                ball.speed = getattr(ball, "speed", 100) * 1.1
                if hasattr(ball, "base_speed"):
                    ball.base_speed *= 1.1

            if hasattr(world, "add_event"):
                world.add_event("level_up", {"ball": getattr(ball, "id", None), "level": ball.level, "stat": stat})


    def _handle_reflect_bounce(self, original_attacker, initial_target, damage: float, bounce_chance: float = 0.5, max_bounces: int = 3, bounce_range: float = 120.0) -> None:
        import random
        import math

        if random.random() > bounce_chance:
            return

        if not hasattr(self.world, "balls"):
            return

        current_source = original_attacker
        hit_targets = {getattr(original_attacker, "id", None), getattr(initial_target, "id", None)}

        for _ in range(max_bounces):
            closest_dist = bounce_range + 1
            next_target = None

            for other in self.world.balls:
                other_id = getattr(other, "id", None)
                if getattr(other, "alive", False) and other_id not in hit_targets and getattr(other, "team", None) == getattr(original_attacker, "team", None) and other_id != getattr(original_attacker, "id", None):
                    dx = getattr(other, "x", 0) - getattr(current_source, "x", 0)
                    dy = getattr(other, "y", 0) - getattr(current_source, "y", 0)
                    dist = math.sqrt(dx*dx + dy*dy)
                    if dist <= bounce_range and dist < closest_dist:
                        closest_dist = dist
                        next_target = other

            if next_target:
                hit_targets.add(getattr(next_target, "id", None))
                if hasattr(self, "_spawn_directed_particles"):
                    self._spawn_directed_particles(next_target, current_source, "chain_lightning")

                if hasattr(self.world, "_deal_damage"):
                    old_dmg = getattr(initial_target, "damage", damage)
                    initial_target.damage = damage * 0.75 # Lose 25% damage per bounce
                    self.world._deal_damage(next_target, initial_target)
                    initial_target.damage = old_dmg
                elif hasattr(next_target, "take_damage"):
                    next_target.take_damage(damage * 0.75)

                damage *= 0.75
                current_source = next_target
            else:
                break

    def _attempt_damage(self, attacker, target) -> None:

        # Elemental Chain Reactions mode logic
        mode = getattr(self.world, 'mode', None)
        mode_name = getattr(mode, 'name', '') if mode else getattr(self.world, 'current_mode_name', '')
        if not mode_name and hasattr(self.world, 'game_mode'):
            mode_name = getattr(self.world.game_mode, 'name', '')

        if mode_name == "Elemental Chain Reactions":
            # Check attacker element
            att_type = getattr(attacker, "ball_type", getattr(attacker, "kind", ""))
            att_traits = [str(t).lower() for t in getattr(attacker, "traits", [])]
            att_element = getattr(attacker, "element", "")

            is_water = att_element == "water" or "water" in att_type or "swamp" in att_type or "puddle" in att_type or any(t in ["water", "swamp"] for t in att_traits)
            is_fire = att_element == "fire" or "fire" in att_type or "lava" in att_type or "flare" in att_type or any(t in ["fire", "lava"] for t in att_traits)

            # Hitting a burning ball with a water attack
            if is_water and getattr(target, "burn_timer", 0.0) > 0:
                target.burn_timer = 0.0
                # steam explosion blinds everyone nearby
                if hasattr(self.world, "add_event"):
                    self.world.add_event("explosion", {"x": target.x, "y": target.y, "radius": 300.0, "damage": 0.0, "type": "steam"})

                if hasattr(self.world, "balls"):
                    for b in self.world.balls:
                        if getattr(b, "alive", True):
                            dist_sq = (b.x - target.x)**2 + (b.y - target.y)**2
                            if dist_sq < 300.0**2:
                                b.blindness_timer = max(getattr(b, "blindness_timer", 0.0), 4.0)
                                b.is_blinded = True
                # do not return early, let normal damage happen

            # Hitting a frozen ball with a fire attack
            if is_fire and getattr(target, "frozen_timer", 0.0) > 0:
                target.frozen_timer = 0.0
                if hasattr(self.world, "add_event"):
                    self.world.add_event("visual_effect", {"type": "ice_shatter", "x": target.x, "y": target.y})

                # massive burst damage
                burst_damage = 150.0
                if hasattr(target, "take_damage"):
                    target.take_damage(burst_damage)
                elif hasattr(target, "hp"):
                    target.hp -= burst_damage
                # do not return early, let normal damage happen
        if getattr(target, "ball_type", "") == "chroma_boss":
            boss_aura = getattr(target, "cosmetic_aura_color", None)
            attacker_aura = getattr(attacker, "cosmetic_aura_color", None)
            if boss_aura and attacker_aura:
                def is_same_color(c1, c2):
                    return all(abs(c1[i] - c2[i]) < 0.01 for i in range(min(3, len(c1), len(c2))))
                if is_same_color(boss_aura, attacker_aura):
                    heal_amt = float(getattr(attacker, "damage", 10.0))
                    attacker.hp = min(getattr(attacker, "hp", 100.0) + heal_amt, getattr(attacker, "max_hp", 100.0))
                    if hasattr(self.world, "add_event"):
                        self.world.add_event("chroma_boss_heal", {"x": getattr(attacker, "x", 0), "y": getattr(attacker, "y", 0)})
                    return

        if getattr(attacker, "in_mirror_dimension", False) != getattr(target, "in_mirror_dimension", False):
            return

        is_projectile_or_laser = getattr(attacker, "ball_type", getattr(attacker, "kind", "")) in ["projectile", "spell", "laser_beam", "spinning_laser", "laser_wall", "bounce_laser", "laser_tripwire"] or getattr(attacker, "is_projectile", False) or getattr(attacker, "is_ricochet_laser", False) or getattr(attacker, "is_spell", False)


        if getattr(target, "has_kinetic_absorber", False):
            # Absorb kinetic energy instead of taking damage
            # We assume a fixed amount of energy per damage attempt or use damage value
            dmg = float(getattr(attacker, "damage", 10.0))
            if hasattr(attacker, "mass"):
                # if attacker has mass (push force), add to energy
                speed = 0.0
                if hasattr(attacker, "vx") and hasattr(attacker, "vy"):
                    import math
                    speed = math.hypot(attacker.vx, attacker.vy)
                dmg += speed * getattr(attacker, "mass", 1.0) * 0.01
            target.kinetic_energy_pool = getattr(target, "kinetic_energy_pool", 0.0) + dmg
            return
        if getattr(target, "is_reflective", False) and is_projectile_or_laser:
            # Prevent damage
            # Attempt to find nearest enemy to reflect towards
            if hasattr(self.world, "get_nearby_entities"):
                nearby = self.world.get_nearby_entities(target, 600.0)
                if isinstance(nearby, dict):
                    enemies = nearby.get("enemies", [])
                    alive_enemies = [e for e in enemies if getattr(e, "alive", False) and getattr(e, "id", None) != target.id]
                    if alive_enemies:
                        import math
                        nearest_enemy = min(alive_enemies, key=lambda e: math.hypot(e.x - target.x, e.y - target.y))
                        # Make projectile turn towards nearest enemy
                        if hasattr(attacker, "vx") and hasattr(attacker, "vy"):
                            dx = nearest_enemy.x - target.x
                            dy = nearest_enemy.y - target.y
                            dist = math.hypot(dx, dy)
                            if dist > 0.001:
                                speed = math.hypot(attacker.vx, attacker.vy)
                                if speed == 0:
                                    speed = 300.0
                                attacker.vx = (dx / dist) * speed
                                attacker.vy = (dy / dist) * speed

                        # Change ownership so it damages enemies instead of target
                        attacker.team = getattr(target, "team", getattr(target, "ball_type", ""))
                        attacker.owner_id = target.id

            return


        if getattr(attacker, "phase_booster_timer", 0.0) > 0.0:
            return

        if getattr(target, "is_shuffler_clone", False):
            if getattr(attacker, "team", "") != getattr(target, "team", ""):
                if hasattr(self.world, "add_event"):
                    self.world.add_event("explosion", {"x": target.x, "y": target.y, "radius": 50.0, "damage": 0.0})
                if hasattr(attacker, "is_blinded"):
                    attacker.is_blinded = True
                    attacker.blindness_timer = max(getattr(attacker, "blindness_timer", 0.0), 3.0)
                else:
                    attacker.is_blinded = True
                    attacker.blindness_timer = 3.0

        if getattr(target, "intangible", False) or getattr(target, "intangible_timer", 0.0) > 0.0:
            if getattr(target, "ghost_mode_active", False):
                is_proj = getattr(attacker, "ball_type", getattr(attacker, "kind", "")) in ["projectile", "spell"] or getattr(attacker, "is_projectile", False) or getattr(attacker, "is_spell", False)
                is_energy = getattr(attacker, "is_energy", False) or getattr(attacker, "damage_type", "") == "energy"
                if is_proj and not is_energy:
                    return # Immune to non-energy projectiles
                elif not is_proj:
                    return # Intangible dodges physical melee/collisions
            else:
                return
        if getattr(attacker, "intangible", False) or getattr(attacker, "intangible_timer", 0.0) > 0.0:
            return
        if getattr(target, "quantum_state_timer", 0.0) > 0.0:
            return

        # Surprise Attack multiplier from bush
        multiplier = 1.0
        if getattr(attacker, "in_bush", False):
            attacker.in_bush = False # Reveal after attack
            multiplier = 1.5


        a_team = getattr(attacker, "team", getattr(attacker, "ball_type", ""))
        t_team = getattr(target, "team", getattr(target, "ball_type", ""))
        if a_team == t_team and a_team != -1 and getattr(attacker, "id", None) != getattr(target, "id", None):
            if getattr(target, "friendly_fire_reflect_timer", 0.0) > 0.0:
                if hasattr(attacker, "take_damage"):
                    attacker.take_damage(getattr(attacker, "damage", 10.0))
                elif hasattr(attacker, "hp"):
                    attacker.hp -= getattr(attacker, "damage", 10.0)
                return
        import random
        if getattr(attacker, 'ball_type', getattr(attacker.__class__, 'BALL_TYPE', '')).lower() == 'alchemist' and random.random() < 0.25:
            # 25% chance to apply a weak stacking poison effect
            target.poison_timer = getattr(target, 'poison_timer', 0.0) + 2.0
            # A weak poison, base damage is handled in game loop, but let's just make it tick damage or something
            target.dot_duration = getattr(target, 'dot_duration', 0.0) + 2.0
            target.dot_damage_per_tick = getattr(target, 'dot_damage_per_tick', 0.0) + 2.0


        # Intercept damage logic for shield_drone
        if getattr(attacker, "blood_magic_timer", 0.0) > 0.0 and random.random() < 0.2:
            target.stun_timer = getattr(target, "stun_timer", 0.0) + 0.5
            if hasattr(self, "_spawn_directed_particles"):
                self._spawn_directed_particles(attacker, target, "blood_magic_stun")

        if getattr(target, 'ball_type', '') != 'shield_drone':
            if hasattr(self.world, 'get_nearby_entities'):
                nearby = self.world.get_nearby_entities(target, 150.0)
                if isinstance(nearby, dict):
                    allies = nearby.get("allies", [])
                    pm = getattr(self.world, "profile_manager", None)
                    for a in allies:
                        if getattr(a, 'ball_type', '') == 'shield_drone' and getattr(a, 'hp', 0) > 0 and getattr(a, 'alive', False):
                            is_n = False
                            if pm and hasattr(pm, "is_nemesis") and getattr(target, "ball_type", None) and getattr(a, "ball_type", None):
                                is_n = pm.is_nemesis(target.ball_type, a.ball_type)
                            if not is_n:
                                original_damage = getattr(attacker, "damage", 10.0)
                                a.take_damage(original_damage)
                                return
        import random
        if getattr(target, "spotlight_damage_multiplier", 1.0) > 1.0:
            multiplier *= getattr(target, "spotlight_damage_multiplier", 1.0)

        # Check if blocked by energy barrier for ranged attacks
        import math
        a_x = getattr(attacker, 'x', 0.0)
        a_y = getattr(attacker, 'y', 0.0)
        t_x = getattr(target, 'x', 0.0)
        t_y = getattr(target, 'y', 0.0)
        dist = math.hypot(a_x - t_x, a_y - t_y)
        a_rad = getattr(attacker, 'radius', 10.0)
        t_rad = getattr(target, 'radius', 10.0)

        # Consider ranged if distance is greater than melee range + small buffer
        is_ranged = dist > (a_rad + t_rad + 20.0)

        if is_ranged:
            gm = getattr(self.world, "game_mode", None)
            if gm and getattr(gm, "name", "") == "Physics Anomaly Event" and getattr(gm, "event_active", False):
                if not hasattr(attacker, "suspended_projectiles"):
                    attacker.suspended_projectiles = []
                is_resuming = getattr(attacker, "_is_resuming_projectile", False)
                if not is_resuming:
                    import math
                    dx = getattr(target, 'x', 0.0) - getattr(attacker, 'x', 0.0)
                    dy = getattr(target, 'y', 0.0) - getattr(attacker, 'y', 0.0)
                    dist = math.hypot(dx, dy)
                    vx = 0.0
                    vy = 0.0
                    if dist > 0.01:
                        vx = (dx / dist) * 800.0
                        vy = (dy / dist) * 800.0

                    attacker.suspended_projectiles.append({
                        "target": target,
                        "timer": 3.0,
                        "x": getattr(attacker, 'x', 0.0),
                        "y": getattr(attacker, 'y', 0.0),
                        "vx": vx,
                        "vy": vy,
                        "is_anomaly": True
                    })
                    return

            if hasattr(self.world, "arena") and hasattr(self.world.arena, "hazards"):
                a_team = getattr(attacker, "team", getattr(attacker, "ball_type", ""))
                for h in self.world.arena.hazards:
                    if getattr(h, 'is_disabled_by_flare', False):
                        continue
                    if getattr(h, "kind", "") in ["orbital_debris", "bone_wall"]:
                        hx = h.x
                        hy = h.y
                        hr = getattr(h, "radius", 40.0)
                        l2 = (t_x - a_x)**2 + (t_y - a_y)**2
                        if l2 == 0:
                            dist_to_line = math.hypot(hx - a_x, hy - a_y)
                        else:
                            t = max(0, min(1, ((hx - a_x) * (t_x - a_x) + (hy - a_y) * (t_y - a_y)) / l2))
                            proj_x = a_x + t * (t_x - a_x)
                            proj_y = a_y + t * (t_y - a_y)
                            dist_to_line = math.hypot(hx - proj_x, hy - proj_y)
                        if dist_to_line <= hr:
                            if getattr(h, "kind", "") == "bone_wall" and hasattr(h, "hp"):
                                h.hp -= getattr(attacker, "damage", 10.0)
                                if h.hp <= 0:
                                    h.active = False
                            return
                    elif getattr(h, "kind", "") in ["slow_motion_zone", "time_bubble"]:
                        hx = h.x
                        hy = h.y
                        hr = getattr(h, "radius", 50.0)

                        dx = t_x - a_x
                        dy = t_y - a_y
                        fx = a_x - hx
                        fy = a_y - hy

                        a = dx*dx + dy*dy
                        b2 = 2 * (fx*dx + fy*dy)
                        c = (fx*fx + fy*fy) - hr*hr

                        if a != 0:
                            disc = b2*b2 - 4*a*c
                            if disc >= 0:
                                disc = math.sqrt(disc)
                                t1 = (-b2 - disc) / (2*a)
                                t2 = (-b2 + disc) / (2*a)
                                if (0 <= t1 <= 1) or (0 <= t2 <= 1) or (t1 < 0 and t2 > 1):
                                    if not hasattr(attacker, "suspended_projectiles"):
                                        attacker.suspended_projectiles = []
                                    # To prevent infinite suspension recursion, we check if this projectile is already resuming.
                                    # But we don't pass a flag easily, so we just check if it's already in the list for this target...
                                    # Actually, a simple way is just:
                                    is_resuming = getattr(attacker, "_is_resuming_projectile", False)
                                    if not is_resuming:
                                        timer_val = 2.0
                                        if getattr(h, "kind", "") == "time_bubble":
                                            timer_val = 4.0
                                        attacker.suspended_projectiles.append({
                                            "target": target,
                                            "timer": timer_val
                                        })
                                        return
                    elif getattr(h, "kind", "") in ["energy_barrier", "smokescreen"]:
                        h_team = getattr(h, "team", "")
                        if h_team != a_team:
                            hx = h.x
                            hy = h.y
                            hr = getattr(h, "radius", 40.0)
                            if getattr(h, "kind", "") == "smokescreen":
                                hr = getattr(h, "radius", 80.0)

                            dx = t_x - a_x
                            dy = t_y - a_y
                            fx = a_x - hx
                            fy = a_y - hy

                            a = dx*dx + dy*dy
                            b2 = 2 * (fx*dx + fy*dy)
                            c = (fx*fx + fy*fy) - hr*hr

                            if a != 0:
                                disc = b2*b2 - 4*a*c
                                if disc >= 0:
                                    disc = math.sqrt(disc)
                                    t1 = (-b2 - disc) / (2*a)
                                    t2 = (-b2 + disc) / (2*a)
                                    if (0 <= t1 <= 1) or (0 <= t2 <= 1) or (t1 < 0 and t2 > 1):
                                        # Attack is blocked by barrier

                                        # Optional: visual effect for shield blocking projectile
                                        if hasattr(self.world, "events"):
                                            intersect_t = t1 if 0 <= t1 <= 1 else t2
                                            ix = a_x + dx * intersect_t
                                            iy = a_y + dy * intersect_t
                                            self.world.events.append({'type': 'visual_effect', 'data': {'type': 'shield_block', 'x': ix, 'y': iy}})

                                        return
                            else:
                                if c <= 0:
                                    return

        # Check attack accuracy
        attack_accuracy = getattr(attacker, "attack_accuracy", 1.0)

        pm = getattr(self.world, "profile_manager", None)
        is_nemesis_active = False
        if pm and hasattr(pm, "is_nemesis") and getattr(attacker, "ball_type", None) and getattr(target, "ball_type", None):
            is_nemesis_active = pm.is_nemesis(attacker.ball_type, target.ball_type)


        if getattr(target, "projectile_reflect_active", False) and is_ranged:
            if not hasattr(target, "suspended_projectiles"):
                target.suspended_projectiles = []

            target.suspended_projectiles.append({
                "x": target.x,
                "y": target.y,
                "target": attacker,
                "damage": getattr(attacker, "damage", 10.0),
                "speed": 600.0,
                "type": "reflected_projectile"
            })
            if hasattr(self.world, "events"):
                self.world.events.append({'type': 'visual_effect', 'data': {'type': 'shield_block', 'x': target.x, 'y': target.y}})
            return

        if getattr(target, "bounce_shield_active", False):
            if is_ranged:
                if not hasattr(target, "suspended_projectiles"):
                    target.suspended_projectiles = []

                target.suspended_projectiles.append({
                    "x": target.x,
                    "y": target.y,
                    "target": attacker,
                    "damage": getattr(attacker, "damage", 10.0),
                    "speed": 800.0,
                    "type": "reflected_projectile"
                })
            else:
                original_damage = getattr(attacker, "damage", 10.0)
                if hasattr(attacker, "take_damage"):
                    attacker.take_damage(original_damage)
                elif hasattr(attacker, "hp"):
                    attacker.hp -= original_damage

            if hasattr(self.world, "events"):
                self.world.events.append({'type': 'visual_effect', 'data': {'type': 'shield_block', 'x': target.x, 'y': target.y}})
            return

        if getattr(target, "kinetic_shield_active", False) and is_ranged:
            # Absorb ranged attack
            inc_dmg = getattr(attacker, "damage", 10.0)
            target.kinetic_shield_stored_damage = getattr(target, "kinetic_shield_stored_damage", 0.0) + inc_dmg
            if hasattr(self.world, "events"):
                self.world.events.append({'type': 'visual_effect', 'data': {'type': 'shield_block', 'x': target.x, 'y': target.y}})
            return

        if getattr(target, "damage_reflection_active", False):
            original_damage = getattr(attacker, "damage", 10.0)
            refl_dmg = original_damage * 0.5
            if hasattr(attacker, "take_damage"):
                attacker.take_damage(refl_dmg)
            elif hasattr(attacker, "hp"):
                attacker.hp -= refl_dmg
            # Target absorbs all damage (takes 0)
            return

        if getattr(target, "half_reflect_shield_active", False):
            original_damage = getattr(attacker, "damage", 10.0)
            refl_dmg = original_damage * 0.5
            if hasattr(attacker, "take_damage"):
                attacker.take_damage(refl_dmg)
            elif hasattr(attacker, "hp"):
                attacker.hp -= refl_dmg
            return
        if getattr(target, "surge_shield_active", False):
            inc_dmg = getattr(attacker, "damage", 10.0)
            target.speed_boost_timer = getattr(target, "speed_boost_timer", 0.0) + 3.0
            target.max_stamina = getattr(target, "max_stamina", 100.0) + inc_dmg
            target.stamina = getattr(target, "stamina", 0.0) + inc_dmg
            if hasattr(self.world, "events"):
                self.world.events.append({'type': 'visual_effect', 'data': {'type': 'shield_block', 'x': target.x, 'y': target.y}})
            return
        if getattr(target, "energy_shield_active", False):

            import math
            a_x = getattr(attacker, 'x', 0.0)
            a_y = getattr(attacker, 'y', 0.0)
            t_x = getattr(target, 'x', 0.0)
            t_y = getattr(target, 'y', 0.0)
            dist = math.hypot(a_x - t_x, a_y - t_y)
            a_rad = getattr(attacker, 'radius', 10.0)
            t_rad = getattr(target, 'radius', 10.0)

            if dist > (a_rad + t_rad + 20.0):
                reflection_mult = 1.5
            else:
                reflection_mult = 0.5

            refl_dmg = getattr(attacker, "damage", 10.0) * reflection_mult

            if hasattr(attacker, "take_damage"):
                attacker.take_damage(refl_dmg)
            elif hasattr(attacker, "hp"):
                attacker.hp -= refl_dmg
            return
        old_hp = getattr(target, "hp", 0.0)

        # Slight damage reduction if target is on ice patch
        damage_reduction = 1.0

        if hasattr(self.world, "arena") and hasattr(self.world.arena, "hazards"):
            for h in self.world.arena.hazards:
                if getattr(h, 'is_disabled_by_flare', False):
                    continue
                if getattr(h, "kind", "") in ("ice_patch", "ice_patches") and getattr(h, "active", True):
                    dx = h.x - getattr(target, "x", 0.0)
                    dy = h.y - getattr(target, "y", 0.0)
                    if dx*dx + dy*dy < getattr(h, "radius", 0.0)**2:
                        damage_reduction = 0.8
                        break

        original_damage = getattr(attacker, "damage", 10.0) * damage_reduction

        # Damage multiplier if attacker is sliding on ice patch
        if hasattr(self.world, "arena") and hasattr(self.world.arena, "hazards"):
            for h in self.world.arena.hazards:
                if getattr(h, 'is_disabled_by_flare', False):
                    continue
                if getattr(h, "kind", "") in ("ice_patch", "ice_patches") and getattr(h, "active", True):
                    dx = h.x - getattr(attacker, "x", 0.0)
                    dy = h.y - getattr(attacker, "y", 0.0)
                    if dx*dx + dy*dy < getattr(h, "radius", 0.0)**2:
                        vx = getattr(attacker, "vx", 0.0)
                        vy = getattr(attacker, "vy", 0.0)
                        speed_sq = vx*vx + vy*vy
                        if speed_sq > 0:
                            import math
                            speed = math.sqrt(speed_sq)
                            original_damage *= (1.0 + (speed / 100.0))
                        break

        if getattr(attacker, "kinetic_shield_stored_damage", 0.0) > 0 and not is_ranged:
            stored_dmg = attacker.kinetic_shield_stored_damage
            original_damage += stored_dmg
            # Apply speed boost
            attacker.speed_boost_timer = getattr(attacker, "speed_boost_timer", 0.0) + 3.0
            # Remove shield
            attacker.kinetic_shield_active = False
            attacker.kinetic_shield_stored_damage = 0.0

        if getattr(target, "takes_double_damage", False):
            original_damage *= 2.0

        if getattr(attacker, "has_sniper_stance", False) and is_ranged:
            a_vx = getattr(attacker, "vx", 0.0)
            a_vy = getattr(attacker, "vy", 0.0)
            if a_vx * a_vx + a_vy * a_vy > 10.0:  # Attacker is moving
                original_damage *= 1.5

        if hasattr(target, "weakness"):
            b_type = getattr(attacker, "ball_type", "").lower()
            traits = getattr(attacker, "traits", [])
            w = target.weakness
            if w in b_type or w in traits:
                original_damage *= 1.5

        if random.random() > attack_accuracy:
            return

        if hasattr(attacker, "tag_team_id") or getattr(attacker, "ball_type", "") == "spectator":
            attacker.tag_recent_hit_timer = 2.0

        if is_ranged:
            # Apply slight knockback/recoil to the attacker for evasive movement
            recoil_force = original_damage * 10.0
            import math
            dx = getattr(target, 'x', 0.0) - getattr(attacker, 'x', 0.0)
            dy = getattr(target, 'y', 0.0) - getattr(attacker, 'y', 0.0)
            dist_sq = dx*dx + dy*dy
            if dist_sq > 0:
                dist = math.sqrt(dist_sq)
                nx = dx / dist
                ny = dy / dist
                attacker.vx = getattr(attacker, 'vx', 0.0) - nx * recoil_force
                attacker.vy = getattr(attacker, 'vy', 0.0) - ny * recoil_force

        executed_by_necromancer = False
        b_type_attacker = getattr(attacker, 'ball_type', getattr(attacker.__class__, 'BALL_TYPE', '')).lower()
        if b_type_attacker == 'necromancer':
            target_max_hp = getattr(target, 'max_hp', 100.0)
            if old_hp > 0 and (old_hp / target_max_hp) < 0.2:
                if random.random() < 0.25:
                    executed_by_necromancer = True

        if executed_by_necromancer:
            if hasattr(self.world, "_deal_damage"):
                old_dmg = getattr(attacker, "damage", original_damage)
                attacker.damage = old_hp + 999.0
                self.world._deal_damage(attacker, target)
                attacker.damage = old_dmg

            target_max_hp = getattr(target, 'max_hp', 100.0)
            attacker.hp = min(getattr(attacker, 'max_hp', 100.0), getattr(attacker, 'hp', 100.0) + target_max_hp * 0.5)
            attacker.reflect_shield_active = True
            attacker.reflect_shield_capacity = max(getattr(attacker, 'reflect_shield_capacity', 0.0), target_max_hp * 0.5 + getattr(attacker, "bonus_reflect_shield_capacity", 0.0))
            attacker.reflect_shield_initial_capacity = attacker.reflect_shield_capacity
            attacker.reflect_shield_timer = 5.0 + getattr(attacker, "bonus_reflect_shield_duration", 0.0)
        else:
            if is_nemesis_active:
                attacker.damage = original_damage * 1.2

            b_type_attacker = getattr(attacker, 'ball_type', getattr(attacker.__class__, 'BALL_TYPE', '')).lower()
            if b_type_attacker == 'bounty_hunter' and (getattr(target, 'is_bounty', False) or getattr(target, 'high_threat', False) or getattr(target, 'is_bounty_target', False)):
                attacker.damage = original_damage * 2.0

            has_ricochet = getattr(target, "ricochet_barrier_timer", 0.0) > 0.0
            has_reflect_shield = getattr(target, "reflect_shield_active", False)
            # Note: in Python tests reflect_shield_timer might not be set.
            if hasattr(target, "reflect_shield_timer") and getattr(target, "reflect_shield_timer", 0.0) <= 0 and has_reflect_shield:
                has_reflect_shield = False

            # Calculate base damage dealing
            if has_ricochet:
                if hasattr(self.world, "_deal_damage"):
                    self.world._deal_damage(target, attacker)
            elif has_reflect_shield:
                # Shield consumes on use and reflects damage
                capacity = getattr(target, "reflect_shield_capacity", 50.0)
                initial_cap_val = getattr(target, "reflect_shield_initial_capacity", capacity)
                max_layers = getattr(target, "reflect_shield_max_layers", 1)

                if max_layers > 1:
                    current_layers = getattr(target, "reflect_shield_current_layers", max_layers)
                    layer_capacity = initial_cap_val / float(max_layers)

                    damage_to_reflect = min(layer_capacity, original_damage)
                    current_layers -= 1
                    target.reflect_shield_current_layers = current_layers
                    target.reflect_shield_capacity = current_layers * layer_capacity

                    original_damage = 0.0 # blocks the instance of damage

                    if current_layers <= 0:
                        target.reflect_shield_active = False
                        target.reflect_shield_capacity = 0.0
                        target.reflect_shield_timer = 0.0
                        capacity = 0.0 # for downstream check
                    else:
                        capacity = target.reflect_shield_capacity # prevent explosion logic

                else:
                    # Reflect only the damage that the shield can absorb
                    damage_to_reflect = min(capacity, original_damage)
                    capacity -= original_damage

                if capacity <= 0 and max_layers <= 1:
                    target.reflect_shield_active = False
                    target.reflect_shield_capacity = 0.0
                    target.reflect_shield_timer = 0.0

                    initial = getattr(target, "reflect_shield_initial_capacity", 0)

                    # Violent shatter check
                    if initial > 0 and original_damage > initial * 1.5:
                        import math
                        explosion_radius = 150.0
                        explosion_damage = original_damage * 1.5

                        # Massive stun to attacker
                        attacker.stun_timer = max(getattr(attacker, "stun_timer", 0.0), 3.0)
                        if hasattr(self.world, "add_event"):
                            self.world.add_event("stun", {"id": getattr(attacker, "id", None), "duration": 3.0})
                            self.world.add_event("explosion", {"x": target.x, "y": target.y, "radius": explosion_radius, "damage": explosion_damage})

                        # AoE damage to all nearby entities
                        if hasattr(self.world, "balls"):
                            for b in self.world.balls:
                                if getattr(b, "alive", True): # Affects allies too
                                    dist = math.hypot(target.x - b.x, target.y - b.y)
                                    if dist <= explosion_radius:
                                        if hasattr(self.world, "_deal_damage"):
                                            old_atk_dmg = getattr(target, "damage", 10.0)
                                            target.damage = explosion_damage
                                            self.world._deal_damage(target, b)
                                            target.damage = old_atk_dmg
                                        elif hasattr(b, "take_damage"):
                                            b.take_damage(explosion_damage)
                                        elif hasattr(b, "hp"):
                                            b.hp -= explosion_damage
                                            if b.hp <= 0:
                                                b.alive = False
                    elif initial > 0 and initial != 999999.0:
                        if hasattr(self.world, "add_event"):
                            self.world.add_event("explosion", {"x": target.x, "y": target.y, "radius": 150.0, "damage": initial * 0.5})
                        if hasattr(self.world, "balls"):
                            for b in self.world.balls:
                                if b != target and getattr(b, "alive", True):
                                    dist = ((target.x - b.x)**2 + (target.y - b.y)**2)**0.5
                                    if dist <= 150.0:
                                        if hasattr(self.world, "_deal_damage"):
                                            old_atk_dmg = getattr(target, "damage", 10.0)
                                            target.damage = initial * 0.5
                                            self.world._deal_damage(target, b)
                                            target.damage = old_atk_dmg
                                        elif hasattr(b, "take_damage"):
                                            b.take_damage(initial * 0.5)
                                        elif hasattr(b, "hp"):
                                            b.hp -= initial * 0.5
                elif max_layers <= 1:
                    target.reflect_shield_capacity = capacity

                # Spawn a pulse particle effect towards the attacker
                if hasattr(self, "_spawn_directed_particles"):
                    self._spawn_directed_particles(target, attacker, "reflect_pulse")

                if hasattr(self.world, "_deal_damage"):
                    # We need a way to deal partial damage.
                    # For now we'll just temporarily adjust attacker damage or similar,
                    # but it seems _deal_damage uses attacker.damage.

                    # We temporarily set the attacker's damage to the reflected amount
                    old_dmg = getattr(attacker, "damage", original_damage)
                    attacker.damage = damage_to_reflect

                    import math
                    explosion_radius = getattr(target, "reflect_explosion_radius", 150.0)
                    targets_to_hit = []
                    if hasattr(self.world, "balls"):
                        for other in self.world.balls:
                            if getattr(other, "alive", False) and getattr(other, "team", getattr(other, "ball_type", "")) != getattr(target, "team", getattr(target, "ball_type", "")):
                                dist = math.hypot(getattr(other, "x", 0) - getattr(target, "x", 0), getattr(other, "y", 0) - getattr(target, "y", 0))
                                if dist <= explosion_radius:
                                    targets_to_hit.append(other)
                    if targets_to_hit:
                        split_dmg = damage_to_reflect / len(targets_to_hit)
                        for e in targets_to_hit:
                            target_old_dmg = getattr(target, "damage", 10.0)
                            target.damage = split_dmg
                            self.world._deal_damage(target, e)
                            target.damage = target_old_dmg

                    attacker.damage = old_dmg

                # If the shield broke, the remainder of the damage applies to the target
                if capacity < 0:
                    remainder_damage = -capacity
                    old_dmg = getattr(attacker, "damage", original_damage)
                    attacker.damage = remainder_damage
                    if hasattr(self.world, "_deal_damage"):
                        self.world._deal_damage(attacker, target)
                    attacker.damage = old_dmg

                    # Overload explosion
                    import math
                    explosion_radius = 80.0
                    if hasattr(self.world, "balls"):
                        for other in self.world.balls:
                            if getattr(other, "alive", False) and getattr(other, "id", None) != getattr(target, "id", None):
                                dx = getattr(other, "x", 0) - getattr(target, "x", 0)
                                dy = getattr(other, "y", 0) - getattr(target, "y", 0)
                                dist = math.sqrt(dx*dx + dy*dy)
                                if dist <= explosion_radius:
                                    if hasattr(self.world, "_deal_damage"):
                                        old_atk_dmg = getattr(target, "damage", 10.0)
                                        target.damage = remainder_damage
                                        self.world._deal_damage(target, other)
                                        target.damage = old_atk_dmg
                                    elif hasattr(other, "take_damage"):
                                        other.take_damage(remainder_damage)
                                    elif hasattr(other, "hp"):
                                        other.hp -= remainder_damage
                                        if hasattr(other, 'hp') and other.hp <= 0:
                                            other.alive = False
            else:
                if hasattr(self.world, "_deal_damage"):
                    old_dmg = getattr(attacker, "damage", 10.0)
                    try:
                        attacker.damage = original_damage
                    except AttributeError:
                        setattr(attacker, "damage", original_damage)
                    self.world._deal_damage(attacker, target)
                    try:
                        attacker.damage = old_dmg
                    except AttributeError:
                        setattr(attacker, "damage", old_dmg)

            if getattr(attacker, "supercharge_stun_ready", False):
                target.stutter_timer = max(getattr(target, "stutter_timer", 0.0), 1.0)
                attacker.supercharge_stun_ready = False

            if getattr(attacker, "leech_booster_timer", 0.0) > 0:
                target.leech_seed_timer = 5.0
                target.leech_seed_attacker_id = getattr(attacker, "id", None)
            if getattr(attacker, "laser_sight_timer", 0.0) > 0:
                if hasattr(attacker, "skill_timer"):
                    attacker.skill_timer = max(0.0, attacker.skill_timer - 0.5)

            if getattr(attacker, "fire_attachment_timer", 0.0) > 0:
                target.dot_duration = getattr(target, 'dot_duration', 0.0) + 2.0
                target.dot_damage_per_tick = getattr(target, 'dot_damage_per_tick', 0.0) + 2.0

            if getattr(attacker, "ice_attachment_timer", 0.0) > 0:
                target.slow_timer = getattr(target, "slow_timer", 0.0) + 2.0

            if getattr(attacker, "spread_attachment_timer", 0.0) > 0:
                for other in getattr(self.world, "balls", []):
                    if getattr(other, "alive", False) and getattr(other, "id", None) != getattr(target, "id", None) and getattr(other, "id", None) != getattr(attacker, "id", None):
                        # only damage enemies
                        a_team = getattr(attacker, "team", getattr(attacker, "ball_type", ""))
                        o_team = getattr(other, "team", getattr(other, "ball_type", ""))
                        if a_team != o_team:
                            import math
                            dx = getattr(other, "x", 0) - getattr(target, "x", 0)
                            dy = getattr(other, "y", 0) - getattr(target, "y", 0)
                            if math.sqrt(dx*dx + dy*dy) <= 60.0:
                                if hasattr(other, "take_damage"):
                                    other.take_damage(original_damage * 0.5)
                                elif hasattr(other, "hp"):
                                    other.hp -= original_damage * 0.5
                                    if other.hp <= 0:
                                        other.alive = False

            if getattr(attacker, "pierce_attachment_timer", 0.0) > 0:
                import math
                ax, ay = getattr(attacker, "x", 0), getattr(attacker, "y", 0)
                tx, ty = getattr(target, "x", 0), getattr(target, "y", 0)
                dx, dy = tx - ax, ty - ay
                dist_at = math.sqrt(dx*dx + dy*dy)
                if dist_at > 0.001:
                    nx, ny = dx/dist_at, dy/dist_at
                    for other in getattr(self.world, "balls", []):
                        if getattr(other, "alive", False) and getattr(other, "id", None) != getattr(target, "id", None) and getattr(other, "id", None) != getattr(attacker, "id", None):
                            a_team = getattr(attacker, "team", getattr(attacker, "ball_type", ""))
                            o_team = getattr(other, "team", getattr(other, "ball_type", ""))
                            if a_team != o_team:
                                ox, oy = getattr(other, "x", 0), getattr(other, "y", 0)
                                odx, ody = ox - tx, oy - ty
                                dist_ot = math.sqrt(odx*odx + ody*ody)
                                if dist_ot > 0.001 and dist_ot <= 100.0:
                                    onx, ony = odx/dist_ot, ody/dist_ot
                                    dot_prod = nx*onx + ny*ony
                                    if dot_prod > 0.7:  # roughly behind target
                                        if hasattr(other, "take_damage"):
                                            other.take_damage(original_damage * 0.5)
                                        elif hasattr(other, "hp"):
                                            other.hp -= original_damage * 0.5
                                            if other.hp <= 0:
                                                other.alive = False

            if getattr(attacker, "bomb_booster_timer", 0.0) > 0:
                target.time_bomb_timer = 5.0
                target.time_bomb_attacker_id = getattr(attacker, "id", None)
                attacker.bomb_booster_timer = 0.0  # Consumed on first attack

            # Apply chain damage modifier if magnetic storm is active
            if hasattr(self.world, "game_mode") and getattr(self.world.game_mode, "weather", "") == "magnetic_storm":
                import math
                chain_radius = 100.0
                chain_chance = 0.5
                if random.random() < chain_chance:
                    chain_damage = original_damage * 0.5
                    nearby_entities = []
                    if hasattr(self.world, "balls"):
                        for b in self.world.balls:
                            if getattr(b, "alive", False) and getattr(b, "id", None) != getattr(target, "id", None) and getattr(b, "id", None) != getattr(attacker, "id", None):
                                d_sq = (getattr(b, "x", 0) - getattr(target, "x", 0))**2 + (getattr(b, "y", 0) - getattr(target, "y", 0))**2
                                if d_sq <= chain_radius**2:
                                    nearby_entities.append((d_sq, b))
                    if hasattr(self.world, "arena") and hasattr(self.world.arena, "hazards"):
                        for h in self.world.arena.hazards:
                            if getattr(h, 'is_disabled_by_flare', False):
                                continue
                            if getattr(h, "active", True) and getattr(h, "id", None) != getattr(target, "id", None):
                                d_sq = (getattr(h, "x", 0) - getattr(target, "x", 0))**2 + (getattr(h, "y", 0) - getattr(target, "y", 0))**2
                                if d_sq <= chain_radius**2:
                                    nearby_entities.append((d_sq, h))

                    if nearby_entities:
                        nearby_entities.sort(key=lambda x: x[0])
                        next_target = nearby_entities[0][1]
                        old_dmg = getattr(attacker, "damage", original_damage)
                        attacker.damage = chain_damage
                        if hasattr(self.world, "_deal_damage"):
                            self.world._deal_damage(attacker, next_target)
                        elif hasattr(next_target, "hp"):
                            next_target.hp -= chain_damage
                        if hasattr(next_target, "stun_timer"):
                            next_target.stun_timer = max(getattr(next_target, "stun_timer", 0.0), 0.2)
                        else:
                            next_target.stun_timer = 0.2
                        attacker.damage = old_dmg
                        if hasattr(self, "_spawn_skill_particles"):
                            self._spawn_skill_particles("lightning")

            if is_nemesis_active or b_type_attacker == "bounty_hunter":
                attacker.damage = original_damage

        new_hp = getattr(target, "hp", 0.0)

        damage_dealt_general = max(0, old_hp - new_hp)
        if damage_dealt_general > 0 and getattr(attacker, "has_vampiric_aura", False):
            heal_amount = damage_dealt_general * 0.5
            attacker.hp = min(getattr(attacker, 'hp', 100.0) + heal_amount, getattr(attacker, 'max_hp', 100.0))

        if b_type_attacker == 'leech':
            damage_dealt = max(0, old_hp - new_hp)
            if damage_dealt > 0:
                heal_amount = damage_dealt * 2.0
                attacker.hp = min(getattr(attacker, 'hp', 100.0) + heal_amount, getattr(attacker, 'max_hp', 100.0))

        # Apply Necromancer healing on attack logic
        # Check if attacker is necromancer and if so, check for minions within range
        b_type = getattr(attacker, 'ball_type', getattr(attacker.__class__, 'BALL_TYPE', '')).lower()
        if b_type == 'necromancer' and new_hp < old_hp: # dealt damage
            has_minion = False
            if hasattr(self.world, "balls"):
                for b in self.world.balls:
                    if getattr(b, "ball_type", "") == "minion" and getattr(b, "team", "") == getattr(attacker, "team", ""):
                        dx = getattr(b, "x", 0) - getattr(attacker, "x", 0)
                        dy = getattr(b, "y", 0) - getattr(attacker, "y", 0)
                        if dx*dx + dy*dy < 40000:  # 200 radius
                            has_minion = True
                            break
            if has_minion:
                actual_damage_dealt = old_hp - new_hp
                if actual_damage_dealt > 0:
                    attacker.hp = min(getattr(attacker, 'hp', 100.0) + actual_damage_dealt * 0.3, getattr(attacker, 'max_hp', 100.0))

        # Award XP for damage dealt and kills
        if new_hp < old_hp:
            self._award_xp(attacker, 10.0, self.world)
            if new_hp <= 0 and old_hp > 0:
                base_xp = 50.0
                if pm and hasattr(pm, "is_nemesis") and getattr(attacker, "ball_type", None) and getattr(target, "ball_type", None):
                    if pm.is_nemesis(target.ball_type, attacker.ball_type):
                        base_xp *= 2.0
                self._award_xp(attacker, base_xp, self.world)

        if new_hp <= 0 and old_hp > 0:
            if b_type_attacker == 'bounty_hunter' and (getattr(target, 'is_bounty', False) or getattr(target, 'high_threat', False) or getattr(target, 'is_bounty_target', False)):
                reward_amt = getattr(target, 'bounty_contract_xp_reward', 500)
                currency_cut = int(reward_amt * 0.1) # 10% of xp as currency
                pm = getattr(self.world, 'profile_manager', None)
                if pm and hasattr(pm, 'data'):
                    pm.data['prestige_tokens'] = pm.data.get('prestige_tokens', 0) + currency_cut
                    pm.save()

            if getattr(target, "is_bounty_target", False):
                owner_id = getattr(target, "bounty_target_owner", None)
                if owner_id is not None:
                    owner = None
                    if hasattr(self.world, "balls"):
                        owner = next((b for b in self.world.balls if getattr(b, "id", None) == owner_id), None)
                    if owner and getattr(owner, "alive", True):
                        self._award_xp(owner, 150.0, self.world)
                        if hasattr(owner, "take_damage"):
                            owner.hp = min(getattr(owner, "max_hp", 100.0), getattr(owner, "hp", 100.0) + 30.0)
                        if hasattr(self.world, "add_event"):
                            self.world.add_event("bounty_trap_claimed", {"message": "Bounty Trap claimed!"})

            if getattr(target, "is_dynamic_bounty", False):
                attacker.damage = getattr(attacker, "damage", 10.0) * 1.5
                if hasattr(attacker, "base_damage"):
                    attacker.base_damage *= 1.5
                attacker.max_hp = getattr(attacker, "max_hp", 100.0) * 1.5
                attacker.hp = min(getattr(attacker, "hp", 100.0) + (attacker.max_hp - attacker.max_hp / 1.5), attacker.max_hp)
                attacker.loadout_fragments = getattr(attacker, "loadout_fragments", 0) + 1
                attacker.is_minor_bounty = True
                if hasattr(self.world, "add_event"):
                    self.world.add_event("dynamic_bounty_claimed", {"message": "Dynamic Bounty claimed!"})
            elif getattr(target, "is_minor_bounty", False):
                attacker.damage = getattr(attacker, "damage", 10.0) * 1.25
                if hasattr(attacker, "base_damage"):
                    attacker.base_damage *= 1.25
                attacker.max_hp = getattr(attacker, "max_hp", 100.0) * 1.25
                attacker.hp = min(getattr(attacker, "hp", 100.0) + (attacker.max_hp - attacker.max_hp / 1.25), attacker.max_hp)
                if hasattr(self.world, "add_event"):
                    self.world.add_event("minor_bounty_claimed", {"message": "Minor Bounty claimed!"})
            if pm and hasattr(pm, "add_kill"):
                pm.add_kill(attacker.ball_type, target.ball_type)
                if pm.is_nemesis(target.ball_type, attacker.ball_type):
                    if hasattr(attacker, "charge_level"):
                        attacker.charge_level = min(100.0, getattr(attacker, "charge_level", 0.0) + 20.0)

            if hasattr(attacker, "kills"):
                attacker.kills += 1
            else:
                attacker.kills = 1

            if b_type_attacker == 'bounty_hunter' and (getattr(target, 'is_bounty', False) or getattr(target, 'high_threat', False) or getattr(target, 'is_bounty_target', False)):
                attacker.hp = getattr(attacker, "max_hp", 100.0)
                attacker.speed_boost_timer = getattr(attacker, "speed_boost_timer", 0.0) + 3.0
                attacker.attack_speed_buff_timer = getattr(attacker, "attack_speed_buff_timer", 0.0) + 3.0

            if hasattr(attacker, "sponsor"):
                if attacker.sponsor == "aggressor":
                    attacker.damage = getattr(attacker, "damage", 10.0) * 1.1
                    if hasattr(attacker, "base_damage"):
                        attacker.base_damage *= 1.1
                elif attacker.sponsor == "vampiric" and getattr(attacker, "kills", 0) % 2 == 0:
                    attacker.hp = min(getattr(attacker, "max_hp", 100.0), getattr(attacker, "hp", 100.0) + 20)
                elif attacker.sponsor == "juggernaut" and getattr(attacker, "kills", 0) % 3 == 0:
                    attacker.max_hp = getattr(attacker, "max_hp", 100.0) * 1.15
                    attacker.hp = getattr(attacker, "hp", 100.0) + getattr(attacker, "max_hp", 100.0) * 0.15
                if hasattr(attacker, "charge_level"):
                    attacker.charge_level = min(100.0, getattr(attacker, "charge_level", 0.0) + 20.0)

            # Drop material on kill
            if hasattr(self.world, "arena") and hasattr(self.world.arena, "items"):
                import random
                mat_type = random.choice(["Iron Ore", "Magic Dust", "Void Shard"])
                new_id = getattr(self.world, "next_id", 9999)
                if hasattr(self.world, "next_id"): self.world.next_id += 1
                mat = {"id": f"mat_{new_id}", "x": getattr(target, "x", 0), "y": getattr(target, "y", 0), "ball_type": "item", "kind": "material", "material_type": mat_type, "radius": 15.0, "active": True}
                self.world.arena.items.append(mat)


        # Chain lightning effect
        if getattr(attacker, "chain_lightning_timer", 0.0) > 0:
            enemies = self._get_enemies()
            hazards = []
            if hasattr(self.world, "arena") and hasattr(self.world.arena, "hazards"):
                hazards = self.world.arena.hazards

            boosters = getattr(self.world, "boosters", [])
            items = []
            if hasattr(self.world, "arena") and hasattr(self.world.arena, "items"):
                items = self.world.arena.items

            if enemies or hazards or boosters or items:
                weather_is_thunderstorm = hasattr(self.world, "arena") and getattr(self.world.arena, "weather", "") == "thunderstorm"
                if not weather_is_thunderstorm and hasattr(self.world, "game_mode") and getattr(self.world.game_mode, "weather", "") == "thunderstorm":
                    weather_is_thunderstorm = True

                chain_range = 150
                chain_damage_multiplier = 0.65

                if weather_is_thunderstorm:
                    chain_range = 300
                    chain_damage_multiplier = 1.05

                chain_range_sq = chain_range * chain_range
                jump_count = 0
                has_original_damage = hasattr(attacker, "damage")
                original_damage = getattr(attacker, "damage", 10.0)
                current_target = target
                current_damage = original_damage * chain_damage_multiplier
                hit_entities = [attacker, target]

                # Micro-stun initial target
                if hasattr(target, "stun_timer"):
                    target.stun_timer = max(getattr(target, "stun_timer", 0.0), 0.2)
                else:
                    target.stun_timer = 0.2

                while jump_count < 4:
                    nearby_entities = []
                    for e in enemies:
                        if e not in hit_entities and getattr(e, "insulator_timer", 0.0) <= 0:
                            dist_sq = (e.x - current_target.x)**2 + (e.y - current_target.y)**2
                            if dist_sq < chain_range_sq:
                                cosmetic = getattr(e, "cosmetic", "").lower().replace(" ", "_")
                                if cosmetic == "grounded_boots" or cosmetic == "lightning_rod":
                                    nearby_entities.append((-999999 + dist_sq, e, "enemy"))
                                else:
                                    nearby_entities.append((dist_sq, e, "enemy"))
                    for h in hazards:
                        if h not in hit_entities and getattr(h, "active", True):
                            dist_sq = (h.x - current_target.x)**2 + (h.y - current_target.y)**2
                            if dist_sq < chain_range_sq:
                                # Attract lightning to emp_trap
                                if getattr(h, "trap_variant", "") == "emp_trap" or getattr(h, "kind", "") in ["lightning_rod", "deployable_lightning_rod"]:
                                    nearby_entities.append((-999999 + dist_sq, h, "hazard")) # High priority
                                else:
                                    nearby_entities.append((dist_sq, h, "hazard"))
                    for b in boosters:
                        if b not in hit_entities:
                            dist_sq = (b.x - current_target.x)**2 + (b.y - current_target.y)**2
                            if dist_sq < chain_range_sq:
                                nearby_entities.append((dist_sq, b, "booster"))
                    for it in items:
                        if it not in hit_entities:
                            dist_sq = (it.x - current_target.x)**2 + (it.y - current_target.y)**2
                            if dist_sq < chain_range_sq:
                                nearby_entities.append((dist_sq, it, "item"))

                    if hasattr(self.world, "arena"):
                        aw = getattr(self.world.arena, "width", 2000.0)
                        ah = getattr(self.world.arena, "height", 2000.0)

                        class WallPoint:
                            def __init__(self, x, y, name):
                                self.x = x
                                self.y = y
                                self.name = name

                        walls = [
                            WallPoint(0.0, current_target.y, "left_wall"),
                            WallPoint(aw, current_target.y, "right_wall"),
                            WallPoint(current_target.x, 0.0, "top_wall"),
                            WallPoint(current_target.x, ah, "bottom_wall")
                        ]
                        for w in walls:
                            if w.name not in hit_entities:
                                dist_sq = (w.x - current_target.x)**2 + (w.y - current_target.y)**2
                                if dist_sq < chain_range_sq:
                                    nearby_entities.append((dist_sq, w, "wall"))

                    if not nearby_entities:
                        break

                    nearby_entities.sort(key=lambda x: x[0])
                    _, next_entity, e_type = nearby_entities[0]

                    attacker.damage = current_damage

                    if e_type == "enemy":
                        e_ricochet = getattr(next_entity, "ricochet_barrier_timer", 0.0) > 0.0
                        e_reflect = getattr(next_entity, "reflect_shield_active", False)

                        if e_ricochet:
                            if hasattr(self.world, "_deal_damage"):
                                self.world._deal_damage(next_entity, attacker)
                        elif e_reflect:
                            capacity = getattr(next_entity, "reflect_shield_capacity", 50.0)
                            damage_to_reflect = min(capacity, current_damage)
                            capacity -= current_damage
                            if capacity <= 0:
                                next_entity.reflect_shield_active = False
                                next_entity.reflect_shield_capacity = 0.0

                                initial = getattr(next_entity, "reflect_shield_initial_capacity", 0)
                                if initial > 0 and current_damage > initial * 1.5:
                                    import math
                                    explosion_radius = 150.0
                                    explosion_damage = current_damage * 1.5

                                    # Massive stun to attacker
                                    attacker.stun_timer = max(getattr(attacker, "stun_timer", 0.0), 3.0)
                                    if hasattr(self.world, "add_event"):
                                        self.world.add_event("stun", {"id": getattr(attacker, "id", None), "duration": 3.0})
                                        self.world.add_event("explosion", {"x": next_entity.x, "y": next_entity.y, "radius": explosion_radius, "damage": explosion_damage})

                                    # AoE damage to all nearby entities
                                    if hasattr(self.world, "balls"):
                                        for b in self.world.balls:
                                            if getattr(b, "alive", True):
                                                dist = math.hypot(next_entity.x - b.x, next_entity.y - b.y)
                                                if dist <= explosion_radius:
                                                    if hasattr(self.world, "_deal_damage"):
                                                        old_atk_dmg = getattr(next_entity, "damage", 10.0)
                                                        next_entity.damage = explosion_damage
                                                        self.world._deal_damage(next_entity, b)
                                                        next_entity.damage = old_atk_dmg
                                                    elif hasattr(b, "take_damage"):
                                                        b.take_damage(explosion_damage)
                                                    elif hasattr(b, "hp"):
                                                        b.hp -= explosion_damage
                                                        if b.hp <= 0:
                                                            b.alive = False
                            else:
                                next_entity.reflect_shield_capacity = capacity

                            if hasattr(self, "_spawn_directed_particles"):
                                self._spawn_directed_particles(next_entity, attacker, "reflect_pulse")
                            if hasattr(self.world, "_deal_damage"):
                                old_dmg = getattr(attacker, "damage", current_damage)
                                attacker.damage = damage_to_reflect
                                self.world._deal_damage(next_entity, attacker)
                                attacker.damage = old_dmg

                                self._handle_reflect_bounce(attacker, next_entity, damage_to_reflect)

                            if capacity < 0:
                                remainder_damage = -capacity
                                old_dmg = getattr(attacker, "damage", current_damage)
                                attacker.damage = remainder_damage
                                if hasattr(self.world, "_deal_damage"):
                                    self.world._deal_damage(attacker, next_entity)
                                attacker.damage = old_dmg

                                # Overload explosion
                                import math
                                explosion_radius = 80.0
                                if hasattr(self.world, "balls"):
                                    for other in self.world.balls:
                                        if getattr(other, "alive", False) and getattr(other, "id", None) != getattr(next_entity, "id", None):
                                            dx = getattr(other, "x", 0) - getattr(next_entity, "x", 0)
                                            dy = getattr(other, "y", 0) - getattr(next_entity, "y", 0)
                                            dist = math.sqrt(dx*dx + dy*dy)
                                            if dist <= explosion_radius:
                                                if hasattr(self.world, "_deal_damage"):
                                                    old_atk_dmg = getattr(next_entity, "damage", 10.0)
                                                    next_entity.damage = remainder_damage
                                                    self.world._deal_damage(next_entity, other)
                                                    next_entity.damage = old_atk_dmg
                                                elif hasattr(other, "take_damage"):
                                                    other.take_damage(remainder_damage)
                                                elif hasattr(other, "hp"):
                                                    other.hp -= remainder_damage
                                                    if other.hp <= 0:

                                                        other.alive = False
                        else:
                            if hasattr(self.world, "_deal_damage"):
                                self.world._deal_damage(attacker, next_entity)
                            if hasattr(next_entity, "stun_timer"):
                                next_entity.stun_timer = max(getattr(next_entity, "stun_timer", 0.0), 0.2)
                            else:
                                next_entity.stun_timer = 0.2
                    elif e_type in ("hazard", "item", "booster"):
                        if getattr(next_entity, "trap_variant", "") == "emp_trap":
                            # Absorb damage and charge
                            charge = getattr(next_entity, "emp_charge", 0.0) + current_damage
                            setattr(next_entity, "emp_charge", charge)
                            if charge >= 50.0:
                                # Trigger EMP burst
                                if getattr(next_entity, "kind", "") == "deployable_lightning_rod":
                                    next_entity.charge = getattr(next_entity, "charge", 0.0) + getattr(attacker, "damage", 10.0) * 2.0
                                else:
                                    setattr(next_entity, "active", False)
                                if hasattr(self.world, "balls"):
                                    for b in self.world.balls:
                                        if getattr(b, "alive", True) and getattr(b, "id", None) != getattr(next_entity, "owner_id", None):
                                            dist_burst = ((b.x - next_entity.x)**2 + (b.y - next_entity.y)**2)**0.5
                                            if dist_burst <= 200.0:
                                                if getattr(b, "emp_immunity_timer", 0.0) <= 0:
                                                    b.is_emped = True
                                                    b.emp_timer = 4.0
                                                    b.silence_timer = max(getattr(b, "silence_timer", 0.0), 3.0)
                                                    if hasattr(b, "skill_timer"):
                                                        b.skill_timer = max(getattr(b, "skill_timer", 0.0), 3.0)
                                                    b.speed = getattr(b, "base_speed", 100.0) * 0.5
                                                    b.is_scrambled = True
                                                    b.scramble_timer = 3.0
                        elif getattr(next_entity, "kind", "") in ["lightning_rod", "deployable_lightning_rod"]:
                            if getattr(next_entity, "kind", "") == "deployable_lightning_rod":
                                next_entity.charge = getattr(next_entity, "charge", 0.0) + getattr(attacker, "damage", 10.0) * 2.0
                            else:
                                setattr(next_entity, "active", False)
                            if hasattr(self.world, "balls"):
                                amplified_damage = current_damage * 2.0
                                valid_targets = [b for b in self.world.balls if getattr(b, "alive", True) and b not in hit_entities]
                                if valid_targets:
                                    valid_targets.sort(key=lambda b: (b.x - next_entity.x)**2 + (b.y - next_entity.y)**2, reverse=True)
                                    for ft in valid_targets[:3]:
                                        if hasattr(self.world, "_deal_damage"):
                                            old_dmg = getattr(attacker, "damage", 10.0)
                                            attacker.damage = amplified_damage
                                            self.world._deal_damage(attacker, ft)
                                            attacker.damage = old_dmg
                                        elif hasattr(ft, "take_damage"):
                                            ft.take_damage(amplified_damage)
                                        elif hasattr(ft, "hp"):
                                            ft.hp -= amplified_damage
                                            if ft.hp <= 0: ft.alive = False

                                        if hasattr(self, "_spawn_directed_particles"):
                                            self._spawn_directed_particles(next_entity, ft, "chain_lightning")
                                        hit_entities.append(ft)
                            # Stop chaining from the rod itself to other nearby things, as it already split to 3
                            jump_count = 3
                            break
                        elif getattr(next_entity, "kind", next_entity.get("kind", "") if isinstance(next_entity, dict) else "") == "material":
                            if getattr(next_entity, "active", next_entity.get("active", False) if isinstance(next_entity, dict) else False):
                                if hasattr(next_entity, "active"): next_entity.active = False
                                elif isinstance(next_entity, dict): next_entity["active"] = False
                                pm = getattr(self.world, "profile_manager", None)
                                if pm and hasattr(pm, "add_material"):
                                    m_type = getattr(next_entity, "material_type", next_entity.get("material_type", "Iron Ore") if isinstance(next_entity, dict) else "Iron Ore")
                                    pm.add_material(m_type, 1)
                        elif hasattr(next_entity, "hp"):
                            next_entity.hp -= current_damage
                            if next_entity.hp <= 0:
                                next_entity.active = False

                    if hasattr(self, "_spawn_skill_particles"):
                        self._spawn_skill_particles("lightning")
                        self._spawn_skill_particles("lightning")

                    if e_type == "wall":
                        hit_entities.append(next_entity.name)
                    else:
                        hit_entities.append(next_entity)

                    current_target = next_entity
                    current_damage *= 0.8
                    jump_count += 1

                # Restore original damage
                if has_original_damage:
                    attacker.damage = original_damage
                else:
                    delattr(attacker, "damage")
    """
    Action execution system.
    Executes the chosen behavior (strategy) by interacting with the ball.
    Handles movement, pathfinding, timing, and cooldowns.
    """
    def __init__(self, ball: Any, world: Any):
        self.ball = ball
        self.world = world

    def _get_perception_radius(self) -> float:
        pr = float(getattr(self.ball, "perception_radius", 250.0))

        # Check for Thermal Goggles loadout item to ignore fog
        cosmetic = getattr(self.ball, "cosmetic", "").lower().replace(" ", "_")
        ignores_fog = cosmetic == "thermal_goggles"
        ignores_rain = cosmetic in ["rain_goggles", "waterproof_goggles"]

        if hasattr(self.world, "arena") and getattr(self.world.arena, "is_raining", False) and not ignores_rain:
            pr *= 0.6  # Reduced perception in rain
        if hasattr(self.world, "arena") and getattr(self.world.arena, "is_foggy", False) and not ignores_fog:
            pr *= 0.4  # Further reduced perception in fog
        return pr


    def execute(self, strategy: str, delta: float) -> None:


        if hasattr(self.ball, "orbital_link_timer"):
            if getattr(self.ball, "orbital_link_timer", 0.0) > 0.0:
                self.ball.orbital_link_timer -= delta
        if not getattr(self.ball, "alive", True) and getattr(self.ball, "ball_type", "") == "ghost":
            self._handle_ghost_behavior(delta)
            return

        if not getattr(self.ball, "alive", True) and getattr(self.ball, "ball_type", "") != "spectator":
            self.ball.ball_type = "ghost"
            self.ball.alive = False
            if hasattr(self.ball, "speed"): self.ball.speed = 100.0
            if hasattr(self.ball, "hp"): self.ball.hp = 0.0
            return


        b_type_initial = getattr(self.ball, "ball_type", getattr(self.ball.__class__, "BALL_TYPE", "")).lower()
        if b_type_initial == "linker" and getattr(self.ball, "link_target", None) is None:
            if hasattr(self.world, "balls"):
                for b in self.world.balls:
                    b_type = getattr(b, "ball_type", getattr(b.__class__, "BALL_TYPE", "")).lower()
                    if getattr(b, "alive", True) and b_type != "spectator" and b.id != getattr(self.ball, "id", None) and getattr(b, "team", b_type) != getattr(self.ball, "team", b_type_initial):
                        self.ball.link_target = b
                        self.ball.max_hp = getattr(b, "max_hp", 100)
                        self.ball.hp = getattr(b, "hp", 100)
                        self.ball.speed = getattr(b, "speed", 5.0)
                        break

        if getattr(self.ball, "is_mounted", False):
            # The ball's HP *is* the mount's HP. If they take damage, ball.hp goes down.
            # Check if mount is destroyed
            if getattr(self.ball, "hp", 0) <= 0:
                self.ball.is_mounted = False
                self.ball.stutter_timer = max(getattr(self.ball, "stutter_timer", 0.0), 2.0)
                if hasattr(self.world, "add_event"):
                    self.world.add_event("vehicle_destroyed", {"ball_id": getattr(self.ball, "id", None)})
                # Restore original stats
                self.ball.hp = getattr(self.ball, "pre_mount_hp", 100)
                self.ball.max_hp = getattr(self.ball, "pre_mount_max_hp", 100)
                self.ball.damage = getattr(self.ball, "pre_mount_damage", 10)
                self.ball.speed = getattr(self.ball, "pre_mount_speed", 100)
            else:
                self.ball.max_hp = getattr(self.ball, "mount_max_hp", 100)
                self.ball.damage = getattr(self.ball, "mount_damage", 10)
                self.ball.speed = getattr(self.ball, "mount_speed", 50)

        else:
            if hasattr(self.world, "arena") and hasattr(self.world.arena, "hazards"):
                for hazard in list(self.world.arena.hazards):
                    if getattr(hazard, "kind", "") == "vehicle_mount":
                        dist_sq = (hazard.x - self.ball.x)**2 + (hazard.y - self.ball.y)**2
                        if dist_sq <= getattr(hazard, "radius", 30)**2:
                            self.ball.is_mounted = True

                            # Save original stats
                            self.ball.pre_mount_hp = getattr(self.ball, "hp", 100)
                            self.ball.pre_mount_max_hp = getattr(self.ball, "max_hp", 100)
                            self.ball.pre_mount_damage = getattr(self.ball, "damage", 10)
                            self.ball.pre_mount_speed = getattr(self.ball, "speed", 100)

                            # Apply mount stats
                            self.ball.mount_max_hp = getattr(hazard, "max_hp", 200)
                            self.ball.hp = getattr(hazard, "hp", 200)
                            self.ball.mount_damage = getattr(hazard, "damage", 50)
                            self.ball.mount_speed = getattr(hazard, "speed", 50)

                            self.world.arena.hazards.remove(hazard)
                            if hasattr(self.world, "add_event"):
                                self.world.add_event("vehicle_mounted", {"ball_id": getattr(self.ball, "id", None)})
                            break

        gm = getattr(self.world, 'game_mode', None)
        if gm and getattr(gm, 'name', '') == 'Custom Match' and getattr(gm, 'mutators_active', False) and 'kinetic_ghost' in getattr(gm, 'mutators', []):
            vx = getattr(self.ball, 'vx', 0.0)
            vy = getattr(self.ball, 'vy', 0.0)
            speed = (vx**2 + vy**2)**0.5
            if speed > getattr(self.ball, 'base_speed', 100.0) * 1.5:
                import random
                if random.random() < 0.2 * delta:
                    self.ball.phase_booster_timer = max(getattr(self.ball, 'phase_booster_timer', 0.0), 0.5)
                    self.ball.hazard_immunity_timer = max(getattr(self.ball, 'hazard_immunity_timer', 0.0), 0.5)

        if getattr(self.ball, "trap_disarm_timer", 0.0) > 0:
            self.ball.trap_disarm_timer -= delta
            if hasattr(self.world, "arena") and hasattr(self.world.arena, "hazards"):
                for hazard in list(self.world.arena.hazards):
                    if getattr(hazard, "kind", "") == "trap":
                        dist_sq = (hazard.x - self.ball.x)**2 + (hazard.y - self.ball.y)**2
                        # 300 radius reveal = 90000 dist sq
                        if dist_sq < 90000:
                            if hasattr(hazard, "active"):
                                hazard.active = True
                            if hasattr(hazard, "duration") and dist_sq < getattr(hazard, "radius", 20.0)**2:
                                hazard.duration = 0.0

        flare_timer = getattr(self.world, 'flare_light_timer', 0.0)
        if isinstance(flare_timer, (int, float)) and flare_timer > 0.0:
            # We decrement based on number of active balls so the total drain matches delta roughly
            ball_count = max(1, len(getattr(self.world, 'balls', [1])))
            self.world.flare_light_timer -= delta / ball_count

        if getattr(self.ball, "ball_type", "") == "solar_bot":
            arena = getattr(self.world, 'arena', None)
            gm = getattr(self.world, 'game_mode', None)

            is_dark = False
            if arena:
                if getattr(arena, 'is_night', False) or getattr(arena, 'is_eclipse', False) or getattr(arena, 'is_lunar_eclipse', False) or getattr(arena, 'is_solar_eclipse', False):
                    is_dark = True
            if gm and getattr(gm, 'is_blackout', False):
                is_dark = True

            is_lit_by_flare = getattr(self.world, 'flare_light_timer', 0.0) > 0.0

            if is_lit_by_flare:
                is_dark = False

            if not hasattr(self.ball, "original_base_speed"):
                self.ball.original_base_speed = getattr(self.ball, "base_speed", getattr(self.ball, "speed", 100.0))
            if not hasattr(self.ball, "original_base_damage"):
                self.ball.original_base_damage = getattr(self.ball, "base_damage", getattr(self.ball, "damage", 10.0))

            if not is_dark:
                self.ball.hp = min(getattr(self.ball, 'max_hp', 100.0), getattr(self.ball, 'hp', 0.0) + 5.0 * delta)
                self.ball.stamina = min(getattr(self.ball, 'max_stamina', 100.0), getattr(self.ball, 'stamina', 0.0) + 20.0 * delta)
                # Restore stats if they were debuffed
                if not getattr(self.ball, 'is_mounted', False):
                    self.ball.speed = getattr(self.ball, 'original_base_speed', 100.0)
                if not getattr(self.ball, 'is_mounted', False):
                    self.ball.damage = getattr(self.ball, 'original_base_damage', 10.0)
            else:
                if not getattr(self.ball, 'is_mounted', False):
                    self.ball.speed = getattr(self.ball, 'original_base_speed', 100.0) * 0.5
                if not getattr(self.ball, 'is_mounted', False):
                    self.ball.damage = getattr(self.ball, 'original_base_damage', 10.0) * 0.5

        if getattr(self.ball, "has_drone", False):
            drone_radius = 150.0
            drone_drain_rate = 5.0 * delta # 5 damage per second per enemy? or total? Let's say per enemy.

            enemies = [e for e in getattr(self.world, "balls", []) if getattr(e, "id", None) != getattr(self.ball, "id", None) and getattr(e, "alive", True) and getattr(e, "team", getattr(e, "ball_type", "")) != getattr(self.ball, "team", getattr(self.ball, "ball_type", ""))]

            total_healed = 0.0
            for e in enemies:
                dist_sq = (self.ball.x - e.x)**2 + (self.ball.y - e.y)**2
                if dist_sq <= drone_radius**2:
                    if hasattr(e, "take_damage"):
                        e.take_damage(drone_drain_rate)
                    elif hasattr(e, "hp"):
                        e.hp -= drone_drain_rate
                        if e.hp <= 0:
                            e.hp = 0
                            e.alive = False
                    total_healed += drone_drain_rate

            if total_healed > 0.0:
                self.ball.hp = min(getattr(self.ball, "hp", 100.0) + total_healed, getattr(self.ball, "max_hp", 100.0))

        if getattr(self.ball, "survival_swap_timer", 0.0) > 0.0:
            self.ball.survival_swap_timer -= delta
            if self.ball.survival_swap_timer <= 0.0:
                self.ball.survival_swap_timer = 0.0
                target_id = getattr(self.ball, "survival_swap_target_id", None)
                if target_id is not None and hasattr(self.world, "balls"):
                    for b in self.world.balls:
                        if getattr(b, "id", None) == target_id and getattr(b, "alive", True) and getattr(b, "is_decoy", False):
                            # Swap positions
                            tx, ty = self.ball.x, self.ball.y
                            self.ball.x, self.ball.y = b.x, b.y
                            b.x, b.y = tx, ty
                            # Apply confusion
                            for enemy in [e for e in getattr(self.world, "balls", []) if getattr(e, "alive", True) and getattr(e, "team", getattr(e, "ball_type", "")) != getattr(self.ball, "team", getattr(self.ball, "ball_type", ""))]:
                                dist_sq = (enemy.x - self.ball.x)**2 + (enemy.y - self.ball.y)**2
                                if dist_sq <= 150.0**2:
                                    enemy.is_confused = True
                                    enemy.confusion_timer = max(getattr(enemy, "confusion_timer", 0.0), 3.0)

                            # Remove decoy
                            b.hp = 0
                            b.alive = False
                            break

        # Necromancer aura logic
        if getattr(self.ball, 'ball_type', getattr(self.ball.__class__, 'BALL_TYPE', '')).lower() == 'necromancer':
            necro_aura_radius = 150.0
            necro_aura_damage = 5.0 * delta # 5 damage per second
            enemies_in_aura = [e for e in getattr(self.world, "balls", []) if e != self.ball and getattr(e, "alive", True) and getattr(e, "team", getattr(e, "ball_type", "")) != getattr(self.ball, "team", getattr(self.ball, "ball_type", ""))]
            total_damage_dealt = 0.0
            for e in enemies_in_aura:
                dist_sq = (self.ball.x - e.x)**2 + (self.ball.y - e.y)**2
                if dist_sq <= necro_aura_radius**2:
                    if hasattr(e, "take_damage"):
                        e.take_damage(necro_aura_damage)
                    elif hasattr(e, "hp"):
                        e.hp -= necro_aura_damage
                        if e.hp <= 0:
                            e.hp = 0
                            e.alive = False
                    total_damage_dealt += necro_aura_damage

            if total_damage_dealt > 0:
                # Convert a portion of damage dealt to heal or bone armor stacks
                conversion = total_damage_dealt * 0.5
                if self.ball.hp < getattr(self.ball, "max_hp", 100.0):
                    self.ball.hp = min(getattr(self.ball, "max_hp", 100.0), self.ball.hp + conversion)
                else:
                    self.ball.bone_armor_timer = getattr(self.ball, "bone_armor_timer", 0.0) + conversion

        if getattr(self.ball, "tracker_booster_timer", 0.0) > 0:
            self.ball.tracker_booster_timer -= delta
            if self.ball.tracker_booster_timer <= 0:
                self.ball.tracker_booster_timer = 0.0
                self.ball.tracker_booster_target = None

        if getattr(self.ball, "is_turret", False) and getattr(self.ball, "is_overclocked", False) and getattr(self.ball, "alive", True):
            self.ball.hp -= 10.0 * delta
            if self.ball.hp <= 0:
                self.ball.hp = 0
                self.ball.alive = False
        if getattr(self.ball, "wall_stick_timer", 0.0) > 0.0:
            self.ball.wall_stick_timer = max(0.0, self.ball.wall_stick_timer - delta)
            if self.ball.wall_stick_timer <= 0.0:
                if getattr(self.ball, "stun_timer", 0.0) <= 0.0:
                    self.ball.is_stunned = False

        if getattr(self.ball, "is_bounty_target", False):
            if hasattr(self.ball, "bounty_target_timer"):
                self.ball.bounty_target_timer -= delta
                if self.ball.bounty_target_timer <= 0:
                    self.ball.is_bounty_target = False

        if getattr(self.ball, "is_stunned", False):
            if getattr(self.ball, "wall_stick_timer", 0.0) > 0.0:
                return

        if hasattr(self.ball, "polarity_cooldown") and type(self.ball.polarity_cooldown) in (int, float) and self.ball.polarity_cooldown > 0:
            self.ball.polarity_cooldown = max(0, self.ball.polarity_cooldown - delta)


        if getattr(self.ball, "ball_type", "") == "shuffler" and not getattr(self.ball, "is_shuffler_clone", False) and getattr(self.ball, "alive", True):
            if abs(getattr(self.ball, "vx", 0.0)) + abs(getattr(self.ball, "vy", 0.0)) > 0.5:
                timer = getattr(self.ball, "shuffler_clone_timer", 2.0)
                timer -= delta
                if timer <= 0:
                    timer = 2.0
                    import copy
                    import random
                    clone = copy.copy(self.ball)
                    clone.id = getattr(self.world, "next_id", random.randint(10000, 99999))
                    if hasattr(self.world, "next_id"):
                        self.world.next_id += 1
                    clone.is_shuffler_clone = True
                    clone.max_hp = 1.0
                    clone.hp = 1.0
                    clone.damage = 0.0
                    clone.vx = getattr(self.ball, "vx", 0.0)
                    clone.vy = getattr(self.ball, "vy", 0.0)
                    if hasattr(self.world, "balls"):
                        self.world.balls.append(clone)
                self.ball.shuffler_clone_timer = timer

        if getattr(self.ball, "is_perfect_mirror", False):
            owner_id = getattr(self.ball, "owner_id", None)
            if owner_id is not None and hasattr(self.world, "balls"):
                owner = next((b for b in self.world.balls if getattr(b, "id", None) == owner_id and getattr(b, "alive", True)), None)
                if owner:
                    arena_w = getattr(self.world.arena, "width", 1000) if hasattr(self.world, "arena") else getattr(self.world, "width", 1000)
                    arena_h = getattr(self.world.arena, "height", 1000) if hasattr(self.world, "arena") else getattr(self.world, "height", 1000)
                    self.ball.x = arena_w - owner.x
                    self.ball.y = arena_h - owner.y
                    self.ball.vx = -getattr(owner, "vx", 0.0)
                    self.ball.vy = -getattr(owner, "vy", 0.0)
            return

        if getattr(self.ball, "is_ricochet_laser", False):
            self.ball.duration -= delta
            if self.ball.duration <= 0 or getattr(self.ball, "bounces_left", 0) <= 0:
                self.ball.alive = False
                return

            self.ball.x += self.ball.vx * delta
            self.ball.y += self.ball.vy * delta

            bounces_left = getattr(self.ball, "bounces_left", 5)
            bounced = False

            # Wall collisions
            if hasattr(self.world, "arena"):
                width = getattr(self.world.arena, "width", 1000)
                height = getattr(self.world.arena, "height", 1000)
            else:
                width = getattr(self.world, "width", 1000)
                height = getattr(self.world, "height", 1000)

            radius = getattr(self.ball, "radius", 5.0)

            if self.ball.x < radius:
                self.ball.x = radius
                self.ball.vx *= -1
                bounced = True
            elif self.ball.x > width - radius:
                self.ball.x = width - radius
                self.ball.vx *= -1
                bounced = True

            if self.ball.y < radius:
                self.ball.y = radius
                self.ball.vy *= -1
                bounced = True
            elif self.ball.y > height - radius:
                self.ball.y = height - radius
                self.ball.vy *= -1
                bounced = True

            if bounced:
                bounces_left -= 1
                setattr(self.ball, "bounces_left", bounces_left)

            # Entity collisions
            if bounces_left > 0:
                import math
                owner_id = getattr(self.ball, "owner_id", None)
                for other in getattr(self.world, "balls", []):
                    if not getattr(other, "alive", True) or getattr(other, "id", None) == getattr(self.ball, "id", None):
                        continue
                    if getattr(other, "id", None) == owner_id:
                        continue

                    dist_sq = (self.ball.x - other.x)**2 + (self.ball.y - other.y)**2
                    r_sum = radius + getattr(other, "radius", 15.0)

                    if dist_sq < r_sum**2:
                        # Hit!
                        last_hit = getattr(self.ball, "last_hit_id", None)
                        base_dmg = getattr(self.ball, "base_damage", 10.0)

                        if getattr(other, "id", None) == last_hit:
                            dmg = getattr(self.ball, "damage", base_dmg) * 2.0
                        else:
                            dmg = base_dmg

                        setattr(self.ball, "damage", dmg)
                        setattr(self.ball, "last_hit_id", getattr(other, "id", None))

                        if hasattr(self.world, "_deal_damage"):
                            self.world._deal_damage(self.ball, other, dmg)
                        elif hasattr(other, "take_damage"):
                            other.take_damage(dmg)
                        elif hasattr(other, "hp"):
                            other.hp -= dmg

                        other.slow_timer = getattr(other, "slow_timer", 0.0) + 1.0

                        # Reflect
                        dist = math.sqrt(dist_sq)
                        if dist > 0.0001:
                            nx = (self.ball.x - other.x) / dist
                            ny = (self.ball.y - other.y) / dist
                            dot = self.ball.vx * nx + self.ball.vy * ny
                            if dot < 0:
                                self.ball.vx = self.ball.vx - 2 * dot * nx
                                self.ball.vy = self.ball.vy - 2 * dot * ny
                        else:
                            self.ball.vx *= -1
                            self.ball.vy *= -1

                        bounces_left -= 1
                        setattr(self.ball, "bounces_left", bounces_left)
                        break

            if bounces_left <= 0:
                self.ball.alive = False
            return


        ball_type = getattr(self.ball, "ball_type", getattr(self.ball.__class__, "BALL_TYPE", ""))
        if ball_type == "trickster":
            if hasattr(self.world, "events"):
                active_decoys = [b for b in getattr(self.world, "balls", []) if (getattr(b, "is_decoy", False) or getattr(b, "is_active_clone", False) or getattr(b, "is_decoy_clone", False)) and (getattr(b, "owner_id", None) == getattr(self.ball, "id", None) or getattr(b, "mimic_owner", None) == getattr(self.ball, "id", None)) and getattr(b, "alive", True)]
                for decoy in active_decoys:
                    if strategy in ["flee", "attack"] or strategy.startswith("flee") or strategy.startswith("attack"):
                        self.world.events.append({
                            "type": "visual_effect",
                            "data": {
                                "type": "decoy_mimic",
                                "x": decoy.x,
                                "y": decoy.y,
                                "mimic_strategy": strategy
                            }
                        })

        if getattr(self.ball, "ghost_mode_timer", 0.0) > 0.0:
            self.ball.ghost_mode_timer -= delta
            if self.ball.ghost_mode_timer <= 0.0:
                self.ball.ghost_mode_timer = 0.0
                if getattr(self.ball, "ghost_mode_active", False):
                    self.ball.intangible = False
                    self.ball.ghost_mode_active = False

        if getattr(self.ball, "amnesia_timer", 0.0) > 0:
            self.ball.amnesia_timer -= delta

        if hasattr(self.ball, "overclock_timer"):
            if self.ball.overclock_timer > 0.0:
                self.ball.overclock_timer = max(0.0, self.ball.overclock_timer - delta)
                if self.ball.overclock_timer <= 0.0:
                    if hasattr(self.ball, "inventory") and "overclock_booster" in self.ball.inventory:
                        self.ball.inventory.remove("overclock_booster")

        if hasattr(self.ball, "gravity_multiplier_timer") and self.ball.gravity_multiplier_timer > 0:
            self.ball.gravity_multiplier_timer -= delta

        if hasattr(self.ball, "gravity_boots_timer"):
            if self.ball.gravity_boots_timer > 0.0:
                self.ball.gravity_boots_timer = max(0.0, self.ball.gravity_boots_timer - delta)
                if self.ball.gravity_boots_timer <= 0.0:
                    if hasattr(self.ball, "inventory") and "gravity_boots" in self.ball.inventory:
                        self.ball.inventory.remove("gravity_boots")

        if hasattr(self.ball, "thermal_boots_timer"):
            if self.ball.thermal_boots_timer > 0.0:
                self.ball.thermal_boots_timer = max(0.0, self.ball.thermal_boots_timer - delta)
                if self.ball.thermal_boots_timer <= 0.0:
                    if hasattr(self.ball, "inventory") and "thermal_boots" in self.ball.inventory:
                        self.ball.inventory.remove("thermal_boots")

        if hasattr(self.ball, "thermal_boots_timer"):
            if self.ball.thermal_boots_timer > 0.0:
                self.ball.thermal_boots_timer = max(0.0, self.ball.thermal_boots_timer - delta)
                if self.ball.thermal_boots_timer <= 0.0:
                    if hasattr(self.ball, "inventory") and "thermal_boots" in self.ball.inventory:
                        self.ball.inventory.remove("thermal_boots")
        if getattr(self.ball, "ball_type", "") == "spectator":
            if strategy.startswith("cheer:"):
                parts = strategy.split(":")
                if len(parts) >= 2:
                    cheer_type = parts[1]
                    cheer_points = getattr(self.ball, "cheer_points", 0)
                    cost = 10
                    if cheer_points >= cost:
                        self.ball.cheer_points -= cost
                        if hasattr(self.world, "arena") and hasattr(self.world.arena, "hazards"):
                            effect = CheerEffect(self.ball.x, self.ball.y, cheer_type, getattr(self.ball, "id", -1))
                            self.world.arena.hazards.append(effect)

        if getattr(self.ball, "ball_type", "") == "broodling":
            import math
            self._update_skill_timer(delta)

            nearby_entities = self.world.get_nearby_entities(self.ball, getattr(self.ball, "perception_radius", 300.0))
            boosters = nearby_entities.get("boosters", [])
            hazards = nearby_entities.get("hazards", [])
            items = [h for h in hazards if getattr(h, "kind", "").endswith("_booster") or getattr(h, "kind", "") in ["cleanser", "health_pack", "rearm_token"]] + boosters

            target_item = None
            if items:
                target_item = min(items, key=lambda i: (i.x - self.ball.x)**2 + (i.y - self.ball.y)**2)

            if target_item:
                dx = target_item.x - self.ball.x
                dy = target_item.y - self.ball.y
                dist = math.hypot(dx, dy)
                if dist > 0.001:
                    spd = getattr(self.ball, "speed", 6.0)
                    self.ball.x += (dx / dist) * spd * delta * 60
                    self.ball.y += (dy / dist) * spd * delta * 60

                dist_sq = dx*dx + dy*dy
                radius_sum = getattr(self.ball, "radius", 5) + getattr(target_item, "radius", 10)
                if dist_sq <= radius_sum**2:
                    is_cursed_mode = hasattr(self.world, "mode") and getattr(self.world.mode, "name", "") == "Cursed Boosters"
                    pre_stats = {}
                    if is_cursed_mode:
                        pre_stats = {
                            "hp": getattr(self.ball, "hp", 100.0),
                            "speed": getattr(self.ball, "speed", 100.0),
                            "damage": getattr(self.ball, "damage", 10.0),
                            "stamina": getattr(self.ball, "stamina", 100.0)
                        }
                    else:
                        pre_stats = {
                            "hp": getattr(self.ball, "hp", 100.0),
                            "speed": getattr(self.ball, "speed", 100.0)
                        }

                    if hasattr(self.world, "_collect_booster"):
                        self.world._collect_booster(self.ball, target_item)

                    post_stats = {
                        "hp": getattr(self.ball, "hp", 100.0),
                        "speed": getattr(self.ball, "speed", 100.0)
                    }
                    if "hp" in pre_stats and post_stats["hp"] > pre_stats["hp"]:
                        target = getattr(self.ball, "entanglement_target", None)
                        if target and getattr(self.ball, "entanglement_timer", 0.0) > 0.0:
                            if hasattr(target, "hp"):
                                diff = post_stats["hp"] - pre_stats["hp"]
                                target.hp = min(getattr(target, "hp", 100.0) + diff * 0.5, getattr(target, "max_hp", 100.0))
                    if "speed" in pre_stats and post_stats["speed"] > pre_stats["speed"]:
                        target = getattr(self.ball, "entanglement_target", None)
                        if target and getattr(self.ball, "entanglement_timer", 0.0) > 0.0:
                            if hasattr(target, "speed"):
                                diff = post_stats["speed"] - pre_stats["speed"]
                                target.speed = getattr(target, "speed", 100.0) + diff * 0.5

                    if is_cursed_mode:
                        post_hp = getattr(self.ball, "hp", 100.0)
                        if post_hp > pre_stats["hp"]:
                            self.ball.hp = pre_stats["hp"] - (post_hp - pre_stats["hp"])
                        post_speed = getattr(self.ball, "speed", 100.0)
                        if post_speed > pre_stats["speed"]:
                            self.ball.speed = pre_stats["speed"] - (post_speed - pre_stats["speed"])
                            self.ball.slow_timer = getattr(self.ball, "slow_timer", 0.0) + 5.0
                        post_damage = getattr(self.ball, "damage", 10.0)
                        if post_damage > pre_stats["damage"]:
                            self.ball.damage = pre_stats["damage"] - (post_damage - pre_stats["damage"])
                        post_stamina = getattr(self.ball, "stamina", 100.0)
                        if post_stamina > pre_stats["stamina"]:
                            self.ball.stamina = pre_stats["stamina"] - (post_stamina - pre_stats["stamina"])
                    if target_item in boosters and target_item in self.world.boosters:
                        self.world.boosters.remove(target_item)
                    elif target_item in hazards and target_item in getattr(getattr(self.world, "arena", None), "hazards", []):
                        self.world.arena.hazards.remove(target_item)
            else:
                allies = [b for b in getattr(self.world, "balls", []) if getattr(b, "team", "") == getattr(self.ball, "team", "") and b.id != self.ball.id and getattr(b, "ball_type", "") != "broodling" and getattr(b, "hp", 0) < getattr(b, "max_hp", 100) and getattr(b, "alive", True)]
                if allies:
                    target_ally = min(allies, key=lambda a: a.hp / a.max_hp if a.max_hp > 0 else 1.0)
                    dx = target_ally.x - self.ball.x
                    dy = target_ally.y - self.ball.y
                    dist = math.hypot(dx, dy)
                    if dist > 0.001:
                        spd = getattr(self.ball, "speed", 6.0)
                        self.ball.x += (dx / dist) * spd * delta * 60
                        self.ball.y += (dy / dist) * spd * delta * 60
                    if dist < getattr(self.ball, "radius", 5) + getattr(target_ally, "radius", 10) + 5:
                        print("HEALING ALLY", target_ally)
                        print("HEALING", target_ally)
                        target_ally.hp = min(target_ally.max_hp, target_ally.hp + 20.0)
                        self.ball.hp = 0
                        self.ball.alive = False
                else:
                    self._idle(delta)

            self._resolve_collisions()
            self._clamp_position()
            return

        self.ball.is_in_mud = False
        self.ball.is_in_lava = False
        self.ball.is_in_flood_zone = False
        self.ball.is_in_poison_cloud = False
        if getattr(self.ball, "intangible_timer", 0.0) > 0.0:
            self.ball.intangible_timer -= delta
            if self.ball.intangible_timer <= 0.0:
                self.ball.intangible_timer = 0.0
                self.ball.intangible = False
                self.ball.ghost_mode_active = False
        if hasattr(self.ball, "suspended_projectiles"):
            gm = getattr(self.world, "game_mode", None)
            cx = 500.0
            cy = 500.0
            if gm and getattr(gm, "name", "") == "Physics Anomaly Event":
                cx = getattr(gm, "cx", 500.0)
                cy = getattr(gm, "cy", 500.0)

            for sp in list(self.ball.suspended_projectiles):
                sp["timer"] -= delta
                if sp.get("is_anomaly", False):
                    import math
                    sp["x"] += sp.get("vx", 0.0) * delta
                    sp["y"] += sp.get("vy", 0.0) * delta

                    dx = cx - sp["x"]
                    dy = cy - sp["y"]
                    dist = math.hypot(dx, dy)
                    if dist > 0.01:
                        ndx = dx / dist
                        ndy = dy / dist
                        tx = -ndy
                        ty = ndx
                        force_mag = 400.0 * delta
                        sp["vx"] += tx * force_mag
                        sp["vy"] += ty * force_mag

                        target = sp["target"]
                        tdx = getattr(target, 'x', 0.0) - sp["x"]
                        tdy = getattr(target, 'y', 0.0) - sp["y"]
                        tdist = math.hypot(tdx, tdy)
                        t_rad = getattr(target, 'radius', 10.0)

                        if tdist <= (t_rad + 20.0):
                            self.ball.suspended_projectiles.remove(sp)
                            if getattr(target, "alive", True) or getattr(target, "hp", 0) > 0:
                                self.ball._is_resuming_projectile = True
                                self._attempt_damage(self.ball, target)
                                self.ball._is_resuming_projectile = False
                            continue

                if sp["timer"] <= 0:
                    if sp in self.ball.suspended_projectiles:
                        self.ball.suspended_projectiles.remove(sp)
                    if not sp.get("is_anomaly", False):
                        if getattr(sp["target"], "alive", True) or getattr(sp["target"], "hp", 0) > 0:
                            self.ball._is_resuming_projectile = True
                            self._attempt_damage(self.ball, sp["target"])
