                    dist = math.sqrt((self.ball.x - hazard.x)**2 + (self.ball.y - hazard.y)**2)
                    if dist < (self.ball.radius + hazard.radius):
                        if hazard.kind in ["temporal_rift", "time_rift"]:
                            continue
                        if hazard.kind in ("explosive_barrel", "volatile_barrel"):
                            if not getattr(hazard, "is_exploded", False):
                                if getattr(hazard, "is_decoy_volatile_barrel", False) and getattr(hazard, "owner_id", None) != getattr(self.ball, "id", None):
                                    hazard.is_exploded = True
                                    hazard.decoy_detonated = True
                                bvx = getattr(self.ball, "vx", 0.0)
                                bvy = getattr(self.ball, "vy", 0.0)
                                speed = math.hypot(bvx, bvy)
                                hazard_speed = math.hypot(getattr(hazard, "vx", 0.0), getattr(hazard, "vy", 0.0))

                                if dist > 0:
                                    nx, ny = (self.ball.x - hazard.x) / dist, (self.ball.y - hazard.y) / dist
                                    overlap = (self.ball.radius + hazard.radius) - dist
                                    if overlap > 0:
                                        # Push the barrel
                                        push_speed = max(500.0, speed * 3.0)
                                        hazard.vx = getattr(hazard, "vx", 0.0) - nx * push_speed
                                        hazard.vy = getattr(hazard, "vy", 0.0) - ny * push_speed

                                        self.ball.x += nx * (overlap / 2)
                                        self.ball.y += ny * (overlap / 2)
                                        hazard.x -= nx * (overlap / 2)
                                        hazard.y -= ny * (overlap / 2)

                                if speed > 300.0 or hazard_speed > 300.0 or getattr(self.ball, "active_skill", None) is not None:
                                    hazard.is_exploded = True


                        elif hazard.kind == "chain_reaction_trap":
                            if getattr(hazard, "owner_id", None) == getattr(self.ball, "id", object()):
                                continue

                            # Trap triggered by a non-owner ball
                            hazard.duration = 0.0

                            # Start a chain reaction using a BFS queue
                            traps_to_explode = [hazard]
                            exploded_traps = set([hazard])

                            while traps_to_explode:
                                current_trap = traps_to_explode.pop(0)

                                # Explosion visuals
                                if hasattr(self.world, "events"):
                                    self.world.events.append(('visual_effect', {'type': 'explosion', 'x': current_trap.x, 'y': current_trap.y, 'radius': getattr(current_trap, 'radius', 40.0) * 2, 'color': 'orange'}))

                                # Damage nearby balls
                                explosion_radius = getattr(current_trap, "radius", 40.0) * 2
                                explosion_damage = getattr(current_trap, "damage", 25.0)

                                if hasattr(self.world, "balls"):
                                    for b in self.world.balls:
                                        if not getattr(b, "alive", True):
                                            continue
                                        # Owner is immune to their own trap explosion
                                        if getattr(current_trap, "owner_id", None) == getattr(b, "id", None):
                                            continue

                                        dist_sq = (b.x - current_trap.x)**2 + (b.y - current_trap.y)**2
                                        if dist_sq <= explosion_radius**2:
                                            if hasattr(b, "take_damage"):
                                                b.take_damage(explosion_damage)
                                            elif hasattr(b, "hp"):
                                                b.hp -= explosion_damage
                                                if b.hp <= 0:
                                                    b.alive = False
                                                    if hasattr(self.world, "add_event"):
                                                        self.world.add_event("kill", {"killer_id": getattr(current_trap, "owner_id", -1), "victim_id": getattr(b, "id", -1)})

                                # Find other chain_reaction_traps within range to trigger
                                chain_radius = 200.0
                                if hasattr(self.world, "arena") and hasattr(self.world.arena, "hazards"):
                                    for h in self.world.arena.hazards:
                                        if getattr(h, 'is_disabled_by_flare', False):
                                            continue
                                        if h not in exploded_traps and getattr(h, "kind", "") == "chain_reaction_trap" and getattr(h, "duration", 1.0) > 0:
                                            h_dist_sq = (h.x - current_trap.x)**2 + (h.y - current_trap.y)**2
                                            if h_dist_sq <= chain_radius**2:
                                                h.duration = 0.0
                                                exploded_traps.add(h)
                                                traps_to_explode.append(h)

                        elif hazard.kind == "trap":
                            if getattr(hazard, "owner_id", None) == getattr(self.ball, "id", object()):
                                continue
                            if ball_type != "sniper":
                                trap_variant = getattr(hazard, "trap_variant", "normal")

                                # Dynamic weather-based trap modification
                                weather = getattr(self.world, "game_mode", None)
                                if weather:
                                    weather = getattr(weather, "weather", "")
                                if not weather and hasattr(self.world, "arena"):
                                    weather = getattr(self.world.arena, "weather", "")

                                if trap_variant == "normal":
                                    if weather in ["blizzard", "snow", "ice"]:
                                        trap_variant = "freeze"
                                        hazard.kind = "ice_patch"
                                    elif weather == "thunderstorm":
                                        trap_variant = "emp_trap"
                                    elif weather in ["sandstorm", "desert"]:
                                        hazard.kind = "quicksand"
                                    elif weather == "rain":
                                        hazard.kind = "mud_puddle"
                                    elif weather == "heatwave":
                                        hazard.kind = "lava_pool"

                                if trap_variant == "poison":
                                    # Poison: no slow, but take DoT (e.g. 5 damage per second)
                                    poison_damage = 10.0 * delta if getattr(self.ball, "is_in_quicksand", False) else 5.0 * delta
                                    if hasattr(self.ball, "take_damage"):
                                        self.ball.take_damage(poison_damage)
                                    elif hasattr(self.ball, "hp"):
                                        self.ball.hp -= poison_damage
                                        if self.ball.hp <= 0:
                                            self.ball.alive = False

                                elif trap_variant == "siphon":
                                    siphon_latch = type("Hazard", (), {})()
                                    siphon_latch.id = len(self.world.arena.hazards) + 8500
                                    siphon_latch.x = self.ball.x
                                    siphon_latch.y = self.ball.y
                                    siphon_latch.radius = 0.0
                                    siphon_latch.kind = "siphon_latch"
                                    siphon_latch.duration = 5.0
                                    siphon_latch.target_id = self.ball.id
                                    siphon_latch.owner_id = getattr(hazard, "owner_id", None)
                                    self.world.arena.hazards.append(siphon_latch)
                                    hazard.duration = 0.0
                                elif trap_variant == "hologram":
                                    self.ball.hp -= 15.0
                                    if self.ball.hp <= 0:
                                        self.ball.alive = False

                                    if not getattr(self.ball, "is_stunned", False):
                                        self.ball.is_stunned = True
                                    self.ball.stun_timer = 2.0

                                    if not getattr(self.ball, "is_confused", False):
                                        self.ball.is_confused = True
                                    self.ball.confusion_timer = 3.0
                                elif trap_variant == "blindness":
                                    if not getattr(self.ball, "is_blinded", False):
                                        self.ball.is_blinded = True
                                        self.ball.blindness_timer = 3.0
                                        if not hasattr(self.ball, "base_perception_radius"):
                                            self.ball.base_perception_radius = getattr(self.ball, "perception_radius", 250.0)
                                        self.ball.perception_radius = self.ball.base_perception_radius * 0.2
                                    else:
                                        self.ball.blindness_timer = max(getattr(self.ball, "blindness_timer", 0.0), 3.0)
                                    hazard.duration = 0.0
                                elif trap_variant == "emp":
                                    if getattr(self.ball, "emp_immunity_timer", 0.0) <= 0 and not getattr(self.ball, "is_emped", False):
                                        self.ball.is_emped = True
                                        self.ball.emp_timer = 2.0
                                        # Reset positive buffs and disable abilities by increasing skill_timer
                                        if hasattr(self.ball, "skill_timer"):
                                            self.ball.skill_timer = max(getattr(self.ball, "skill_timer", 0.0), 2.0)

                                        base_speed = getattr(self.ball, "base_speed", 100.0)
                                        if getattr(self.ball, "speed", 0.0) > base_speed:
                                            self.ball.speed = base_speed

                                        if hasattr(self.ball, "damage_multiplier") and self.ball.damage_multiplier > 1.0:
                                            self.ball.damage_multiplier = 1.0
                                elif trap_variant == "emp_trap":
                                    # Absorbs electrical damage, then explodes
                                    # Handled in chain lightning logic; but when stepped on normally, just slow slightly or do nothing until charged
                                    self.ball.x = old_x
                                    self.ball.y = old_y
                                elif trap_variant == "nullifier":
                                    # Nullifier Trap: disables all shields and buffs of all players in a huge radius
                                    if hasattr(self.world, "balls"):
                                        for b in self.world.balls:
                                            if getattr(b, "alive", True):
                                                dist_sq = (b.x - hazard.x)**2 + (b.y - hazard.y)**2
                                                if dist_sq <= 4000000.0:  # 2000 radius squared (huge radius)
                                                    # Remove shields
                                                    if hasattr(b, "reflect_shield_active"): b.reflect_shield_active = False
                                                    if hasattr(b, "half_reflect_shield_active"): b.half_reflect_shield_active = False
                                                    if hasattr(b, "energy_shield_active"): b.energy_shield_active = False
                                                    if hasattr(b, "orbital_shield_active"): b.orbital_shield_active = False
                                                    if hasattr(b, "kinetic_shield_active"): b.kinetic_shield_active = False
                                                    if hasattr(b, "charging_shockwave_shield_active"): b.charging_shockwave_shield_active = False
                                                    if hasattr(b, "shield_booster_active"): b.shield_booster_active = False

                                                    # Remove buffs
                                                    if hasattr(b, "speed_buff_timer"): b.speed_buff_timer = 0.0
                                                    if hasattr(b, "damage_buff_timer"): b.damage_buff_timer = 0.0
                                                    if hasattr(b, "attack_speed_buff_timer"): b.attack_speed_buff_timer = 0.0
                                                    if hasattr(b, "emp_immunity_timer"): b.emp_immunity_timer = 0.0
                                                    if hasattr(b, "hazard_immunity_timer"): b.hazard_immunity_timer = 0.0
                                                    if hasattr(b, "speed_booster_timer"): b.speed_booster_timer = 0.0
                                                    if hasattr(b, "damage_booster_timer"): b.damage_booster_timer = 0.0
                                                    if hasattr(b, "hp_booster_timer"): b.hp_booster_timer = 0.0
                                                    if hasattr(b, "stamina_booster_timer"): b.stamina_booster_timer = 0.0

                                    hazard.duration = 0.0
                                elif trap_variant == "elemental_mine":
                                    import random
                                    element = random.choice(["fire", "poison"])
                                    new_hazard = type("Hazard", (), {})()
                                    new_hazard.id = len(self.world.arena.hazards) + getattr(self, "random", __import__("random")).randint(5000, 9999)
                                    new_hazard.x = hazard.x
                                    new_hazard.y = hazard.y
                                    new_hazard.radius = 80.0
                                    if element == "fire":
                                        new_hazard.kind = "fire_zone"
                                        new_hazard.damage = 10.0
                                    else:
                                        new_hazard.kind = "poison_cloud"
                                        new_hazard.damage = 5.0
                                    new_hazard.duration = 10.0
                                    self.world.arena.hazards.append(new_hazard)
                                    hazard.duration = 0.0

                                elif trap_variant == "mine":
                                    # Black Hole Mine: Pull nearby enemies and physics objects for 3s before detonating
                                    if not getattr(hazard, "is_detonating", False):
                                        hazard.is_detonating = True
                                        hazard.detonation_timer = 3.0
                                        # Keep it active but marked as detonating

                                elif trap_variant == "freeze":
                                    # Freeze: halt for 2 seconds
                                    if not getattr(self.ball, "is_stunned", False):
                                        self.ball.is_stunned = True
                                        self.ball.stun_timer = 2.0
                                    self.ball.x = old_x
                                    self.ball.y = old_y
                                    hazard.duration = 0.0 # Destroy trap
                                elif trap_variant == "stun":
                                    # Stun: fully halt for 1 second if not already stunned
                                    if not getattr(self.ball, "is_stunned", False):
                                        self.ball.is_stunned = True
                                        self.ball.stun_timer = 1.0
                                    # Apply stun effect
                                    self.ball.x = old_x
                                    self.ball.y = old_y
                                elif trap_variant == "pull":
                                    # Create a gravity well hazard where the trap is
                                    if hasattr(self.world, "arena") and hasattr(self.world.arena, "hazards"):
                                        from arena.procedural_arena import Hazard
                                        gw_id = len(self.world.arena.hazards) + 8500
                                        gw = Hazard(gw_id, hazard.x, hazard.y, 200.0, "gravity_well", 0.0)
                                        gw.duration = 4.0
                                        self.world.arena.hazards.append(gw)
                                    hazard.duration = 0.0 # Destroy trap
                                elif trap_variant == "reverse_gravity":
                                    if hasattr(self.world, "arena") and hasattr(self.world.arena, "hazards"):
                                        from arena.procedural_arena import Hazard
                                        rg_id = len(self.world.arena.hazards) + 8600
                                        rg = Hazard(rg_id, hazard.x, hazard.y, 150.0, "reverse_gravity_field", 0.0)
                                        rg.duration = 5.0
                                        setattr(rg, "owner_id", getattr(hazard, "owner_id", -1))
                                        self.world.arena.hazards.append(rg)
                                    hazard.duration = 0.0 # Destroy trap
                                elif trap_variant == "black_hole" or trap_variant == "mini_black_hole":
                                    # Create a black hole hazard where the trap is
                                    if hasattr(self.world, "arena") and hasattr(self.world.arena, "hazards"):
                                        from arena.procedural_arena import Hazard
                                        bh_id = len(self.world.arena.hazards) + 8000
                                        if trap_variant == "mini_black_hole":
                                            bh = Hazard(bh_id, hazard.x, hazard.y, 75.0, "mini_black_hole", 0.0)
                                        else:
                                            bh = Hazard(bh_id, hazard.x, hazard.y, 100.0, "black_hole", 0.0)
                                        bh.duration = 3.0 # Short duration
                                        self.world.arena.hazards.append(bh)
                                    hazard.duration = 0.0 # Destroy trap
                                elif trap_variant == "link":
                                    import random
                                    enemy = None
                                    enemies = []
                                    if hasattr(self.world, "balls"):
                                        for b in self.world.balls:
                                            if b != self.ball and getattr(b, "alive", True):
                                                a_team = getattr(self.ball, "team", getattr(self.ball, "ball_type", ""))
                                                b_team = getattr(b, "team", getattr(b, "ball_type", ""))
                                                if a_team != b_team or a_team == -1 or b_team == -1:
                                                    enemies.append(b)
                                    if enemies:
                                        enemy = random.choice(enemies)
                                        self.ball.trap_link_target = enemy
                                        self.ball.trap_link_timer = 10.0
                                        enemy.trap_link_target = self.ball
                                        enemy.trap_link_timer = 10.0
                                    hazard.duration = 0.0 # Destroy trap
                                elif trap_variant == "tar":
                                    # Tar trap: heavily slow down the ball and create a tar puddle
                                    if hasattr(self.ball, "speed_multiplier"):
                                        self.ball.speed_multiplier *= 0.2
                                    if hasattr(self.ball, "slow_timer"):
                                        self.ball.slow_timer = max(getattr(self.ball, "slow_timer", 0.0), 5.0)
                                    else:
                                        self.ball.slow_timer = 5.0

                                    if hasattr(self.world, "arena") and hasattr(self.world.arena, "hazards"):
                                        from arena.procedural_arena import Hazard
                                        tar_puddle_id = len(self.world.arena.hazards) + 9000
                                        tar_puddle = Hazard(tar_puddle_id, hazard.x, hazard.y, 40.0, "tar_puddle", 0.0)
                                        tar_puddle.duration = 10.0
                                        self.world.arena.hazards.append(tar_puddle)

                                    hazard.duration = 0.0 # Destroy trap
                                elif trap_variant == "anchor":
                                    # Anchor Trap: Disables movement abilities (dash/teleport) for 5 seconds
                                    self.ball.anchor_trap_timer = max(getattr(self.ball, "anchor_trap_timer", 0.0), 5.0)
                                    hazard.duration = 0.0 # Destroy trap
                                elif trap_variant == "jump_pad":
                                    hazard.duration = 0.0 # Destroy trap
                                    import random
                                    import math
                                    angle = random.uniform(0, 2 * math.pi)
                                    speed = 1000.0
                                    self.ball.vx = math.cos(angle) * speed
                                    self.ball.vy = math.sin(angle) * speed
                                elif trap_variant == "ricochet":
                                    hazard.duration = 0.0 # Destroy trap

                                    # Spawn ricochet laser
                                    if hasattr(self.world, "balls"):
                                        import math
                                        dx = self.ball.x - hazard.x
                                        dy = self.ball.y - hazard.y
                                        dist = math.sqrt(dx*dx + dy*dy)
                                        if dist > 0.0001:
                                            nx, ny = dx/dist, dy/dist
                                        else:
                                            nx, ny = 1.0, 0.0

                                        laser = type('MockBall', (), {})()
                                        setattr(laser, "id", getattr(self.world, "next_id", 99999))
                                        if hasattr(self.world, "next_id"):
                                            self.world.next_id += 1
                                        setattr(laser, "ball_type", "projectile")
                                        setattr(laser, "is_ricochet_laser", True)

                                        owner_id = getattr(hazard, "owner_id", None)
                                        setattr(laser, "owner_id", owner_id)
                                        setattr(laser, "team", getattr(hazard, "owner_team", ""))

                                        dmg = getattr(hazard, "damage", 10.0)
                                        setattr(laser, "damage", dmg)
                                        setattr(laser, "base_damage", dmg)

                                        setattr(laser, "bounces_left", 5)
                                        setattr(laser, "last_hit_id", None)
                                        setattr(laser, "duration", 10.0)
                                        setattr(laser, "alive", True)
                                        setattr(laser, "x", hazard.x)
                                        setattr(laser, "y", hazard.y)
                                        setattr(laser, "vx", nx * 500.0)
                                        setattr(laser, "vy", ny * 500.0)
                                        setattr(laser, "radius", 5.0)

                                        self.world.balls.append(laser)
                                elif trap_variant == "chain_lightning":
                                    # Chain Lightning trap: zap the triggering ball and then jump to nearest enemy
                                    if hasattr(self.world, "_deal_damage"):
                                        temp_damage = getattr(hazard, "damage", 10.0)
                                        if temp_damage <= 0:
                                            temp_damage = 25.0
                                        # Deal damage to current ball
                                        hazard.damage = temp_damage
                                        self.world._deal_damage(hazard, self.ball)

                                        # Visual effect for zap
                                        if hasattr(self.world, "events"):
                                            self.world.events.append(('visual_effect', {'type': 'lightning', 'x': hazard.x, 'y': hazard.y, 'tx': self.ball.x, 'ty': self.ball.y}))
                                            self.world.events.append(('visual_effect', {'type': 'explosion', 'x': self.ball.x, 'y': self.ball.y, 'radius': 15, 'color': 'yellow'}))

                                        # Overload mechanic: count bounces
                                        bounce_count = getattr(hazard, "chain_bounce_count", 0) + 1
                                        owner_id = getattr(hazard, "owner_id", None)

                                        if bounce_count > 3:
                                            # Overload Detonation!
                                            if hasattr(self.world, "events"):
                                                self.world.events.append(('visual_effect', {'type': 'explosion', 'x': self.ball.x, 'y': self.ball.y, 'radius': 45, 'color': 'cyan'}))

                                            # AoE damage
                                            balls = getattr(self.world, "balls", getattr(self.world, "entities", []))
                                            for b in balls:
                                                if b == self.ball or not getattr(b, "alive", True):
                                                    continue
                                                if owner_id is not None and getattr(b, "id", None) == owner_id:
                                                    continue
                                                dist_sq = (b.x - self.ball.x)**2 + (b.y - self.ball.y)**2
                                                if dist_sq < 45 * 45:
                                                    b.hp = getattr(b, "hp", 100) - 30.0
                                                    if b.hp <= 0:
                                                        b.alive = False
                                                        if hasattr(self.world, "add_event"):
                                                            self.world.add_event("kill", {"killer_id": owner_id if owner_id is not None else -1, "victim_id": getattr(b, "id", -1)})

                                            # Find owner and put skill on extended cooldown
                                            if owner_id is not None:
                                                for b in balls:
                                                    if getattr(b, "id", None) == owner_id:
                                                        b.skill_timer = getattr(b, "skill_timer", 0) + 10.0
                                                        break
                                        else:
                                            # Try to jump to nearest enemy
                                            balls = getattr(self.world, "balls", getattr(self.world, "entities", []))

                                            best_dist = 200.0 * 200.0 # Jump radius squared
                                            nearest_enemy = None

                                            for b in balls:
                                                if b == self.ball or not getattr(b, "alive", True):
                                                    continue
                                                # Don't jump to owner or their teammates
                                                if owner_id is not None and getattr(b, "id", None) == owner_id:
                                                    continue

                                                dist_sq = (b.x - self.ball.x)**2 + (b.y - self.ball.y)**2
                                                if dist_sq < best_dist:
                                                    best_dist = dist_sq
                                                    nearest_enemy = b

                                            if nearest_enemy:
                                                # Spawn a new jumping trap at current target's position
                                                import random
                                                try:
                                                    from src.arena.procedural_arena import Hazard
                                                    new_trap = Hazard(x=nearest_enemy.x, y=nearest_enemy.y, radius=15.0, kind="trap", damage=max(5.0, temp_damage - 5.0))
                                                    new_trap.duration = 5.0
                                                    new_trap.trap_variant = "chain_lightning"
                                                    new_trap.chain_bounce_count = bounce_count
                                                    if owner_id is not None:
                                                        new_trap.owner_id = owner_id
                                                    if hasattr(self.world, "arena") and hasattr(self.world.arena, "hazards"):
                                                        new_trap.id = len(self.world.arena.hazards) + random.randint(1000, 9000)
                                                        self.world.arena.hazards.append(new_trap)
                                                except Exception:
                                                    pass

                                    hazard.duration = 0.0 # Destroy trap


                                elif trap_variant == "clone" and getattr(self.ball, "ball_type", "") in ("projectile", "spell"):
                                    # Redirect clone towards nearest enemy
                                    owner_id = getattr(hazard, "owner_id", None)
                                    nearest_enemy = None
                                    min_dist = float('inf')
                                    if hasattr(self.world, "balls"):
                                        for b in self.world.balls:

                                            owner = None
                                            if hasattr(self.world, "balls"):
                                                for o in self.world.balls:
                                                    if getattr(o, "id", None) == owner_id:
                                                        owner = o
                                                        break
                                            owner_team = getattr(owner, "team", "") if owner else getattr(self.ball, "team", "")
                                            if getattr(b, "id", None) != owner_id and getattr(b, "alive", True) and getattr(b, "team", "") != owner_team:

                                                dist_sq = (b.x - hazard.x)**2 + (b.y - hazard.y)**2
                                                if dist_sq < min_dist:
                                                    min_dist = dist_sq
                                                    nearest_enemy = b

                                    if nearest_enemy:
                                        import copy
                                        import math
                                        import random
                                        clone = copy.copy(self.ball)
                                        clone.id = getattr(self.world, "next_id", random.randint(10000, 99999))
                                        if hasattr(self.world, "next_id"):
                                            self.world.next_id += 1

                                        clone.x = hazard.x
                                        clone.y = hazard.y
                                        clone.owner_id = owner_id

                                        owner = None
                                        if hasattr(self.world, "balls"):
                                            for b in self.world.balls:
                                                if getattr(b, "id", None) == owner_id:
                                                    owner = b
                                                    break
                                        if owner:
                                            clone.team = getattr(owner, "team", "")
                                        else:
                                            clone.team = getattr(self.ball, "team", "") # Fallback


                                        # But let's actually just aim it at enemy
                                        dx = nearest_enemy.x - clone.x
                                        dy = nearest_enemy.y - clone.y
                                        dist = math.hypot(dx, dy)
                                        if dist > 0:
                                            speed = math.hypot(getattr(self.ball, "vx", 0), getattr(self.ball, "vy", 0))
                                            if speed == 0:
                                                speed = 300.0
                                            clone.vx = (dx / dist) * speed
                                            clone.vy = (dy / dist) * speed

                                        if hasattr(self.world, "balls"):
                                            self.world.balls.append(clone)
                                    hazard.duration = 0.0 # Destroy trap

                                elif trap_variant == "warp":
                                    # Warp trap: teleport the ball to a random location in the arena
                                    import random

                                    my_radius = getattr(self.ball, "radius", 10.0)

                                    arena_w = 1000.0
                                    arena_h = 1000.0
                                    if hasattr(self.world, "arena"):
                                        arena_w = getattr(self.world.arena, "width", 1000.0)
                                        arena_h = getattr(self.world.arena, "height", 1000.0)

                                    import math
                                    angle = random.uniform(0, 2 * math.pi)
                                    dist = random.uniform(0, 500.0)
                                    target_x = self.ball.x + math.cos(angle) * dist
                                    target_y = self.ball.y + math.sin(angle) * dist

                                    clamped_x, clamped_y = target_x, target_y
                                    if hasattr(self.world, "arena") and hasattr(self.world.arena, "clamp_position"):
                                        clamped_x, clamped_y, _ = self.world.arena.clamp_position(target_x, target_y, my_radius)

                                    self.ball.x = clamped_x
                                    self.ball.y = clamped_y

                                    if hasattr(self.world, "events"):
                                        self.world.events.append({"type": "teleport", "data": {"x": self.ball.x, "y": self.ball.y}})

                                    hazard.duration = 0.0 # Destroy trap

                                elif trap_variant == "swap":
                                    owner_id = getattr(hazard, "owner_id", None)
                                    if owner_id is not None:
                                        # Find owner ball
                                        owner = None
                                        balls = getattr(self.world, "balls", getattr(self.world, "entities", []))
                                        for b in balls:
                                            if getattr(b, "id", None) == owner_id:
                                                owner = b
                                                break
                                        if owner and owner != self.ball:
                                            # Swap positions
                                            temp_x, temp_y = owner.x, owner.y
                                            owner.x, owner.y = old_x, old_y
                                            self.ball.x, self.ball.y = temp_x, temp_y
                                    hazard.duration = 0.0 # Destroy trap

                                elif trap_variant == "decoy":
                                    owner_id = getattr(hazard, "owner_id", None)
