                    dx = target.x - self.ball.x
                    dy = target.y - self.ball.y
                    dist = math.sqrt(dx*dx + dy*dy)
                    if dist > 0.0001:
                        inputs = [dx/dist, dy/dist, getattr(self.ball, "hp", 100)/getattr(self.ball, "max_hp", 100), 1.0]
